import { keepPreviousData, useQuery } from '@tanstack/react-query';
import { Task, TaskStatus } from '@/types/tasks';
import { getSupabaseClientResult } from '@/integrations/supabase/client';
import { getVisibleTaskTypes } from '@/shared/lib/tasks/taskConfig';
import { normalizeAndPresentAndRethrow } from '@/shared/lib/errorHandling/runtimeError';
// Removed invalidationRouter - DataFreshnessManager handles all invalidation logic
import { useSmartPollingConfig } from '@/shared/hooks/useSmartPolling';
import { QUERY_PRESETS, STANDARD_RETRY, STANDARD_RETRY_DELAY } from '@/shared/lib/query/queryDefaults';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';
import { useProcessingRefetchGuard } from '@/shared/hooks/tasks/useProcessingRefetchGuard';
import {
  notifyPaginatedTaskFetchFailure,
  notifyPaginatedTaskFetchSuccess,
} from '@/shared/realtime/dataFreshness/taskFetchFreshness';
import {
  fetchPaginatedTasks,
  mapDbTaskToTask,
  type PaginatedTaskQuery,
  type PaginatedTasksResponse as RepositoryPaginatedTasksResponse,
} from '@/shared/hooks/tasks/paginatedTaskRepository';
import { resolveTaskProjectScope } from '@/shared/lib/tasks/resolveTaskProjectScope';

// Types for API responses and request bodies
// Ensure these align with your server-side definitions and Task type in @/types/tasks.ts

interface PaginatedTasksParams {
  projectId?: string | null;
  status?: TaskStatus[];
  limit?: number;
  offset?: number;
  taskType?: string | null; // Filter by specific task type
  allProjects?: boolean; // If true, query across all projects
  allProjectIds?: string[]; // List of project IDs to query when allProjects is true
}

export type PaginatedTasksResponse = RepositoryPaginatedTasksResponse;
function createPaginatedTasksQueryFn(filters: PaginatedTaskQuery, cacheProjectKey: string) {
  return async (): Promise<PaginatedTasksResponse> => {
    try {
      const result = await fetchPaginatedTasks(filters);
      notifyPaginatedTaskFetchSuccess(cacheProjectKey);
      return result;
    } catch (error) {
      notifyPaginatedTaskFetchFailure(cacheProjectKey, error);
      normalizeAndPresentAndRethrow(error, {
        context: 'useTasks.fetchPaginatedTasks',
        showToast: false,
        logData: { cacheProjectKey },
      });
    }
  };
}

// Helper to convert DB row (snake_case) to Task interface (camelCase)
// Exported for use in prefetch utilities
export { mapDbTaskToTask };

// Hook to get a single task by ID
// Uses IMMUTABLE_PRESET since task data rarely changes after creation
export const useGetTask = (taskId: string, projectId?: string | null) => {
  const effectiveProjectId = resolveTaskProjectScope(projectId);

  return useQuery<Task | null, Error>({
    queryKey: taskQueryKeys.single(taskId, effectiveProjectId),
    queryFn: async () => {
      const supabaseResult = getSupabaseClientResult();
      if (!supabaseResult.ok) {
        normalizeAndPresentAndRethrow(supabaseResult.error, {
          context: 'useTasks.useGetTask',
          showToast: false,
          logData: { taskId, projectId: effectiveProjectId },
        });
      }

      const { data, error } = await supabaseResult.client
        .from('tasks')
        .select('*')
        .eq('id', taskId)
        .eq('project_id', effectiveProjectId!)
        .maybeSingle();

      if (error) {
        normalizeAndPresentAndRethrow(error, {
          context: 'useTasks.useGetTask',
          showToast: false,
          logData: { taskId, projectId: effectiveProjectId },
        });
      }

      if (!data) {
        return null;
      }

      return mapDbTaskToTask(data);
    },
    enabled: !!taskId && !!effectiveProjectId,
    // Task data is essentially immutable once created - cache aggressively
    ...QUERY_PRESETS.immutable,
  });
};

// Hook to list tasks with pagination - GALLERY PATTERN
export const usePaginatedTasks = (params: PaginatedTasksParams) => {
  const { projectId, status, limit = 50, offset = 0, taskType, allProjects, allProjectIds } = params;
  const page = Math.floor(offset / limit) + 1;
  const effectiveProjectId: string | null = projectId ?? null;
  const cacheProjectKey = allProjects ? 'all' : effectiveProjectId;
  const safeCacheProjectKey = cacheProjectKey ?? '__no-project__';
  const visibleTaskTypes = getVisibleTaskTypes();
  const smartPollingConfig = useSmartPollingConfig(taskQueryKeys.paginated(safeCacheProjectKey));

  const query = useQuery<PaginatedTasksResponse, Error>({
    queryKey: [...taskQueryKeys.paginated(safeCacheProjectKey), page, limit, status, taskType],
    queryFn: createPaginatedTasksQueryFn({
      allProjects,
      allProjectIds,
      effectiveProjectId,
      status,
      taskType,
      visibleTaskTypes,
      limit,
      offset,
      page,
    }, safeCacheProjectKey),
    enabled: allProjects ? !!allProjectIds?.length : !!effectiveProjectId,
    placeholderData: keepPreviousData,
    ...QUERY_PRESETS.realtimeBacked,
    ...smartPollingConfig,
    refetchIntervalInBackground: true,
    retry: STANDARD_RETRY,
    retryDelay: STANDARD_RETRY_DELAY,
  });

  useProcessingRefetchGuard(status, query);

  return query;
};

/**
 * RealtimeProvider - Manages realtime connection and provides status to the app
 *
 * This provider:
 * 1. Connects to the realtime service when a project is selected
 * 2. Wires raw events from connection → processor → invalidation
 * 3. Exposes connection status to the component tree
 *
 */

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo } from 'react';
import { useProject } from '@/shared/contexts/ProjectContext';
import { getRealtimeConnection } from '@/shared/realtime/RealtimeConnection';
import { realtimeEventProcessor } from '@/shared/realtime/RealtimeEventProcessor';
import { dataFreshnessManager } from '@/shared/realtime/DataFreshnessManager';
import { useRealtimeInvalidation } from '@/shared/hooks/useRealtimeInvalidation';
import type { ConnectionState, ConnectionStatus } from '@/shared/realtime/types';

// =============================================================================
// Context
// =============================================================================

interface RealtimeContextValue {
  /** Current connection status */
  status: ConnectionStatus;
  /** Whether currently connected */
  isConnected: boolean;
  /** Whether connection is in progress */
  isConnecting: boolean;
  /** Whether in a failed state (exhausted retries) */
  isFailed: boolean;
  /** Error message if any */
  error: string | null;
  /** Current reconnect attempt (0 if not reconnecting) */
  reconnectAttempt: number;
  /** Manually trigger reconnection */
  reconnect: () => void;
}

const RealtimeContext = createContext<RealtimeContextValue>({
  status: 'disconnected',
  isConnected: false,
  isConnecting: false,
  isFailed: false,
  error: null,
  reconnectAttempt: 0,
  reconnect: () => {},
});

export const useRealtime = () => useContext(RealtimeContext);

// =============================================================================
// Provider
// =============================================================================

interface RealtimeProviderProps {
  children: React.ReactNode;
}

export function RealtimeProvider({ children }: RealtimeProviderProps) {
  const { selectedProjectId } = useProject();
  const realtimeConnection = useMemo(() => getRealtimeConnection(), []);
  const [connectionState, setConnectionState] = useState<ConnectionState>(() =>
    realtimeConnection.getState()
  );

  // Set up the invalidation hook (subscribes to processed events)
  useRealtimeInvalidation();

  // Wire connection events → processor
  useEffect(() => {
    const unsubscribe = realtimeConnection.onEvent((event) => {
      realtimeEventProcessor.process(event);
    });
    return unsubscribe;
  }, [realtimeConnection]);

  // Subscribe to connection status changes
  useEffect(() => {
    const unsubscribe = realtimeConnection.onStatusChange((state) => {
      setConnectionState(state);
    });
    return unsubscribe;
  }, [realtimeConnection]);

  // Connect/disconnect when project changes
  useEffect(() => {
    if (!selectedProjectId) {
      realtimeConnection.disconnect();
      dataFreshnessManager.reset();
      return;
    }

    realtimeConnection.connect(selectedProjectId);

    return () => {
      // Don't disconnect on cleanup - let the next effect handle it
      // This prevents disconnect/reconnect when the component re-renders
    };
  }, [selectedProjectId, realtimeConnection]);

  // Clean up on unmount
  useEffect(() => {
    return () => {
      realtimeEventProcessor.clear();
    };
  }, []);

  // Manual reconnect function
  const reconnect = useCallback(() => {
    if (selectedProjectId) {
      realtimeConnection.reset();
      realtimeConnection.connect(selectedProjectId);
    }
  }, [selectedProjectId, realtimeConnection]);

  // Derive context value from connection state
  const contextValue: RealtimeContextValue = {
    status: connectionState.status,
    isConnected: connectionState.status === 'connected',
    isConnecting: connectionState.status === 'connecting',
    isFailed: connectionState.status === 'failed',
    error: connectionState.error,
    reconnectAttempt: connectionState.reconnectAttempt,
    reconnect,
  };

  return (
    <RealtimeContext.Provider value={contextValue}>
      {children}
    </RealtimeContext.Provider>
  );
}

/**
 * Utilities for prefetching generation-linked task data.
 *
 * The canonical generation -> task mapping query lives in the generation
 * domain; this module only handles best-effort prefetch.
 */

import { useCallback } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { mapDbTaskToTask } from './useTasks';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';
import { isUuid } from '@/shared/lib/uuid';
import type { GenerationTaskMappingCacheEntry } from '@/shared/lib/tasks/generationTaskRepository';
import { resolveTaskProjectScope } from '@/shared/lib/tasks/resolveTaskProjectScope';
import { prefetchGenerationTaskMapping } from '@/domains/generation/hooks/tasks/useGenerationTaskMapping';

/**
 * Hook to prefetch task data for a generation on hover.
 * Returns a function that can be called onMouseEnter to prefetch
 * both the task ID mapping and the full task data.
 */
export function usePrefetchTaskData() {
  const queryClient = useQueryClient();

  const prefetch = useCallback(async (generationId: string, projectId?: string | null) => {
    const effectiveProjectId = resolveTaskProjectScope(projectId);
    if (!generationId || !effectiveProjectId || !isUuid(generationId)) return;

    // Check if task ID mapping is already cached (including { taskId: null } for no-task generations)
    let taskId: string | null = null;
    const cachedMapping = queryClient.getQueryData(taskQueryKeys.generationMapping(generationId)) as GenerationTaskMappingCacheEntry | undefined;

    if (cachedMapping !== undefined) {
      // Already cached - use the cached value (could be null if no task)
      taskId = cachedMapping.taskId;
    } else {
      // Not cached - fetch the task ID mapping
      try {
        const result = await prefetchGenerationTaskMapping(queryClient, generationId);
        taskId = result?.taskId ?? null;
      } catch {
        return;
      }
    }

    // Prefetch the full task data if we have a task ID and it's not cached
    if (taskId) {
      const cachedTask = queryClient.getQueryData(taskQueryKeys.single(taskId, effectiveProjectId));
      if (!cachedTask) {
        try {
          await queryClient.fetchQuery({
            queryKey: taskQueryKeys.single(taskId, effectiveProjectId),
            queryFn: async () => {
              const { data, error } = await supabase().from('tasks')
                .select('*')
                .eq('id', taskId)
                .eq('project_id', effectiveProjectId)
                .single();

              if (error) throw error;
              // Transform to match useGetTask format
              return mapDbTaskToTask(data);
            },
            staleTime: Infinity,
          });
        } catch {
          // Silently fail - prefetch is best-effort
        }
      }
    }
  }, [queryClient]);

  return prefetch;
}

/**
 * Hook to prefetch a task directly by task ID.
 * Use this when you already have the task ID (e.g., from variant.params.source_task_id).
 */
export function usePrefetchTaskById() {
  const queryClient = useQueryClient();

  const prefetch = useCallback(async (taskId: string, projectId?: string | null) => {
    const effectiveProjectId = resolveTaskProjectScope(projectId);
    if (!taskId || !effectiveProjectId || !isUuid(taskId)) return;

    // Check if already cached
    const cached = queryClient.getQueryData(taskQueryKeys.single(taskId, effectiveProjectId));
    if (cached) {
      return;
    }

    try {
      await queryClient.fetchQuery({
        queryKey: taskQueryKeys.single(taskId, effectiveProjectId),
        queryFn: async () => {
          const { data, error } = await supabase().from('tasks')
            .select('*')
            .eq('id', taskId)
            .eq('project_id', effectiveProjectId)
            .single();

          if (error) throw error;
          return mapDbTaskToTask(data);
        },
        staleTime: Infinity,
      });
    } catch {
      // Silently fail - prefetch is best-effort
    }
  }, [queryClient]);

  return prefetch;
}

/**
 * usePendingGenerationTasks Hook
 *
 * Tracks tasks that are "Queued" or "In Progress" that will create
 * variants or derived generations from a given source generation.
 *
 * Works for both images and videos - checks task params for source generation references.
 */

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { TASK_STATUS } from '@/types/tasks';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';

interface PendingGenerationTask {
  id: string;
  status: string;
  task_type: string;
}

interface UsePendingGenerationTasksReturn {
  /** Number of pending tasks that will create variants/derived from this generation */
  pendingCount: number;
  /** The pending tasks */
  pendingTasks: PendingGenerationTask[];
  /** Loading state */
  isLoading: boolean;
}

/**
 * Check if task params reference a specific generation ID as a source.
 * Checks common param fields where source generation is stored.
 */
export function taskReferencesGeneration(
  params: Record<string, unknown> | null,
  generationId: string
): boolean {
  if (!params || !generationId) return false;

  // Direct source references
  if (params.based_on === generationId) return true;
  if (params.source_generation_id === generationId) return true;
  if (params.generation_id === generationId) return true;
  if (params.input_generation_id === generationId) return true;
  if (params.parent_generation_id === generationId) return true;
  if (params.start_image_generation_id === generationId) return true;
  if (params.end_image_generation_id === generationId) return true;
  // Video segment tasks use pair_shot_generation_id
  if (params.pair_shot_generation_id === generationId) return true;
  if (Array.isArray(params.input_image_generation_ids) && params.input_image_generation_ids.includes(generationId)) {
    return true;
  }

  // Check nested in orchestrator_details
  const orchDetails = params.orchestrator_details as Record<string, unknown> | undefined;
  if (orchDetails) {
    if (orchDetails.based_on === generationId) return true;
    if (orchDetails.source_generation_id === generationId) return true;
    if (orchDetails.parent_generation_id === generationId) return true;
    if (
      Array.isArray(orchDetails.input_image_generation_ids)
      && orchDetails.input_image_generation_ids.includes(generationId)
    ) {
      return true;
    }
    // Check pair_shot_generation_ids array
    if (Array.isArray(orchDetails.pair_shot_generation_ids)) {
      if (orchDetails.pair_shot_generation_ids.includes(generationId)) return true;
    }
  }

  // Check full_orchestrator_payload
  const fullPayload = params.full_orchestrator_payload as Record<string, unknown> | undefined;
  if (fullPayload) {
    if (fullPayload.based_on === generationId) return true;
    if (fullPayload.source_generation_id === generationId) return true;
    if (fullPayload.parent_generation_id === generationId) return true;
  }

  // Check individual_segment_params (used by individual_travel_segment)
  const individualParams = params.individual_segment_params as Record<string, unknown> | undefined;
  if (individualParams) {
    if (individualParams.pair_shot_generation_id === generationId) return true;
  }

  return false;
}

export function usePendingGenerationTasks(
  generationId: string | null | undefined,
  projectId: string | null | undefined
): UsePendingGenerationTasksReturn {
  // Query pending tasks for this project
  const { data: pendingTasks, isLoading } = useQuery({
    queryKey: [...taskQueryKeys.pendingGeneration(generationId!), projectId],
    queryFn: async () => {
      if (!generationId || !projectId) return [];

      // Query tasks that are Queued or In Progress
      const { getSupabaseClient } = await import('@/integrations/supabase/client');
      const { data, error } = await getSupabaseClient().from('tasks')
        .select('id, status, task_type, params')
        .eq('project_id', projectId)
        .in('status', [TASK_STATUS.QUEUED, TASK_STATUS.IN_PROGRESS]);

      if (error) {
        console.error('[usePendingGenerationTasks] Query error:', error);
        return [];
      }

      // Filter to tasks that reference this generation
      const matchingTasks: PendingGenerationTask[] = (data || [])
        .filter(task => taskReferencesGeneration(task.params as Record<string, unknown> | null, generationId))
        .map(task => ({
          id: task.id,
          status: task.status,
          task_type: task.task_type,
        }));

      return matchingTasks;
    },
    enabled: !!generationId && !!projectId,
    // Poll to catch status changes
    refetchInterval: 5000,
    // Mark as stale immediately so invalidations trigger refetch
    staleTime: 0,
    // Short cache time - don't keep stale data around
    gcTime: 10000,
    // Always refetch when window regains focus
    refetchOnWindowFocus: 'always',
  });

  const result = useMemo(() => ({
    pendingCount: pendingTasks?.length || 0,
    pendingTasks: pendingTasks || [],
    isLoading,
  }), [pendingTasks, isLoading]);

  return result;
}

