import { useEffect, useMemo, useState } from "react";
import { useGenerationTaskMapping } from "@/domains/generation/hooks/tasks/useGenerationTaskMapping";
import { useGetTask } from "@/shared/hooks/tasks/useTasks";
import {
  buildTaskDetailsData,
  type TaskDetailsData,
  type TaskDetailsStatus,
} from "@/shared/lib/taskDetails/taskDetailsContract";
import { deriveInputImages, parseTaskParams } from "@/shared/lib/taskParamsUtils";
import { useResolveGenerationTaskMapping } from "@/domains/generation/hooks/tasks/useResolveGenerationTaskMapping";
import { normalizeAndPresentError } from "@/shared/lib/errorHandling/runtimeError";
import type { Task } from "@/types/tasks";
import type {
  GenerationTaskMappingCacheEntry,
} from '@/shared/lib/tasks/generationTaskRepository';

interface UseGenerationTaskDetailsOptions {
  generationId: string | null;
  projectId?: string | null;
  enabled?: boolean;
  resolveMappingOnDemand?: boolean;
  onApplySettingsFromTask?: (taskId: string, replaceImages: boolean, inputImages: string[]) => void;
  onClose?: () => void;
}

interface UseGenerationTaskDetailsResult {
  taskDetailsData: TaskDetailsData | null;
  taskDetailsStatus: TaskDetailsStatus;
  taskMapping: GenerationTaskMappingCacheEntry | undefined;
  taskId: string | null;
  task: Task | undefined;
  inputImages: string[];
  isLoadingTask: boolean;
  taskError: Error | null;
}

export function useGenerationTaskDetails({
  generationId,
  projectId,
  enabled = true,
  resolveMappingOnDemand = false,
  onApplySettingsFromTask,
  onClose,
}: UseGenerationTaskDetailsOptions): UseGenerationTaskDetailsResult {
  const activeGenerationId = enabled ? generationId : null;
  const [fallbackTaskId, setFallbackTaskId] = useState<string | null>(null);
  const [mappingResolutionAttempted, setMappingResolutionAttempted] = useState(false);
  const [mappingResolutionError, setMappingResolutionError] = useState<Error | null>(null);

  useEffect(() => {
    setFallbackTaskId(null);
    setMappingResolutionAttempted(false);
    setMappingResolutionError(null);
  }, [activeGenerationId]);

  const { data: taskMapping, isLoading: isLoadingMapping } = useGenerationTaskMapping(activeGenerationId || "");

  const primaryTaskLookup = useResolveGenerationTaskMapping();
  const shouldResolveOnDemand = (
    Boolean(activeGenerationId)
    && resolveMappingOnDemand
    && taskMapping?.taskId === null
    && taskMapping.status !== "query_failed"
    && fallbackTaskId === null
    && !mappingResolutionAttempted
  );

  useEffect(() => {
    if (!shouldResolveOnDemand || !activeGenerationId) {
      return;
    }
    let cancelled = false;
    setMappingResolutionAttempted(true);

    (async () => {
      try {
        const result = await primaryTaskLookup.mutateAsync(activeGenerationId);
        if (cancelled) return;
        if (result.status === "ok") {
          setMappingResolutionError(null);
          setFallbackTaskId(result.taskId ?? null);
          return;
        }
        if (result.status === "query_failed") {
          const resolutionError = new Error(
            result.queryError ?? "Failed to resolve generation-task mapping",
          );
          setMappingResolutionError(resolutionError);
          normalizeAndPresentError(
            resolutionError,
            {
              context: "useGenerationTaskDetails.resolveMappingOnDemand",
              showToast: false,
              logData: { generationId: activeGenerationId },
            },
          );
        }
      } catch (error) {
        if (cancelled) return;
        const resolutionError = error instanceof Error
          ? error
          : new Error("Failed to resolve generation-task mapping");
        setMappingResolutionError(resolutionError);
        normalizeAndPresentError(error, {
          context: "useGenerationTaskDetails.resolveMappingOnDemand",
          showToast: false,
          logData: { generationId: activeGenerationId },
        });
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [activeGenerationId, primaryTaskLookup, shouldResolveOnDemand]);

  const taskId = taskMapping?.taskId ?? fallbackTaskId ?? null;
  const { data: task, isLoading: isLoadingTaskData, error: taskError } = useGetTask(
    taskId || "",
    projectId,
  );
  const mappingQueryError = useMemo(() => {
    if (taskMapping?.status !== "query_failed") {
      return null;
    }
    return new Error(taskMapping.queryError ?? "Failed to resolve generation-task mapping");
  }, [taskMapping?.queryError, taskMapping?.status]);
  const combinedTaskError = taskError ?? mappingQueryError ?? mappingResolutionError;

  const inputImages = useMemo(() => {
    if (!task?.params) return [];
    return deriveInputImages(parseTaskParams(task.params));
  }, [task]);

  const hasNoTask = taskMapping !== undefined && taskMapping.taskId === null && fallbackTaskId === null;
  const isLoading = hasNoTask
    ? primaryTaskLookup.isPending
    : (isLoadingMapping || isLoadingTaskData || primaryTaskLookup.isPending);
  const taskDetailsStatus: TaskDetailsStatus = useMemo(() => {
    if (!activeGenerationId) {
      return "missing";
    }
    if (combinedTaskError) {
      return "error";
    }
    if (task) {
      return "ok";
    }
    return "missing";
  }, [activeGenerationId, combinedTaskError, task]);

  if (!activeGenerationId) {
    return {
      taskDetailsData: null,
      taskDetailsStatus: "missing",
      taskMapping: undefined,
      taskId: null,
      task: undefined,
      inputImages: [],
      isLoadingTask: false,
      taskError: null,
    };
  }

  return {
    taskDetailsData: buildTaskDetailsData({
      task: task ?? null,
      isLoading,
      status: taskDetailsStatus,
      error: combinedTaskError,
      inputImages,
      taskId,
      onApplySettingsFromTask,
      onClose,
    }),
    taskDetailsStatus,
    taskMapping,
    taskId,
    task,
    inputImages,
    isLoadingTask: isLoadingTaskData,
    taskError: combinedTaskError,
  };
}

import { useQuery } from '@tanstack/react-query';
import { getSupabaseClient } from '@/integrations/supabase/client';
import { getVisibleTaskTypes } from '@/shared/lib/tasks/taskConfig';
import { useSmartPollingConfig } from '@/shared/hooks/useSmartPolling';
import { QUERY_PRESETS, STANDARD_RETRY, STANDARD_RETRY_DELAY } from '@/shared/lib/query/queryDefaults';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';
import { dataFreshnessManager } from '@/shared/realtime/DataFreshnessManager';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import {
  TASK_FAILURE_STATUSES,
  TASK_PROCESSING_STATUSES,
} from '@/shared/lib/tasks/taskStatusSemantics';
import { applyRootTaskFilter } from '@/shared/lib/tasks/orchestratorReference';
import {
  operationFailure,
  operationSuccess,
  type OperationResult,
} from '@/shared/lib/operationResult';

type TaskStatusCountsQuery = 'processing' | 'success' | 'failure';

interface TaskStatusCountsResult {
  processing: number;
  recentSuccesses: number;
  recentFailures: number;
  degraded: boolean;
  failedQueries: TaskStatusCountsQuery[];
  errorCode?: 'task_status_counts_partial_failure';
  operation: OperationResult<{
    processing: number;
    recentSuccesses: number;
    recentFailures: number;
  }>;
}

function buildEmptyTaskStatusCountsResult(): TaskStatusCountsResult {
  const zeroCounts = {
    processing: 0,
    recentSuccesses: 0,
    recentFailures: 0,
  };

  return {
    ...zeroCounts,
    degraded: false,
    failedQueries: [],
    operation: operationSuccess(zeroCounts, { policy: 'best_effort' }),
  };
}

function resolveSettledCountResult(
  projectId: string,
  result: PromiseSettledResult<{ count: number | null; error: unknown }>,
  queryType: TaskStatusCountsQuery,
): { count: number; failed: boolean } {
  if (result.status === 'fulfilled') {
    const { count, error } = result.value;
    if (error) {
      normalizeAndPresentError(error, {
        context: `useTaskStatusCounts.${queryType}`,
        showToast: false,
        logData: { projectId },
      });
      return { count: 0, failed: true };
    }
    return { count: count || 0, failed: false };
  }

  normalizeAndPresentError(
    result.reason instanceof Error ? result.reason : new Error(String(result.reason)),
    {
      context: `useTaskStatusCounts.${queryType}`,
      showToast: false,
      logData: { projectId },
    },
  );
  return { count: 0, failed: true };
}

function buildTaskStatusCountsResult(
  projectId: string,
  counts: { processing: number; success: number; failure: number },
  failedQueries: TaskStatusCountsQuery[],
): TaskStatusCountsResult {
  return {
    processing: counts.processing,
    recentSuccesses: counts.success,
    recentFailures: counts.failure,
    degraded: failedQueries.length > 0,
    failedQueries,
    ...(failedQueries.length > 0
      ? { errorCode: 'task_status_counts_partial_failure' as const }
      : {}),
    operation:
      failedQueries.length > 0
        ? operationFailure(new Error('Task status counts query partially failed'), {
            errorCode: 'task_status_counts_partial_failure',
            policy: 'degrade',
            recoverable: true,
            message: `Partial task status count failure (${failedQueries.join(', ')})`,
            cause: { failedQueries, projectId },
          })
        : operationSuccess(
            {
              processing: counts.processing,
              recentSuccesses: counts.success,
              recentFailures: counts.failure,
            },
            { policy: 'best_effort' },
          ),
  };
}

function trackTaskStatusCountsFreshness(
  projectId: string,
  failedQueries: TaskStatusCountsQuery[],
  settledResults: [
    PromiseSettledResult<{ count: number | null; error: unknown }>,
    PromiseSettledResult<{ count: number | null; error: unknown }>,
    PromiseSettledResult<{ count: number | null; error: unknown }>,
  ],
): void {
  if (failedQueries.length === 0) {
    dataFreshnessManager.onFetchSuccess(taskQueryKeys.statusCounts(projectId));
    return;
  }

  const [processingResult, successResult, failureResult] = settledResults;
  const errorReason =
    processingResult.status === 'rejected'
      ? processingResult.reason
      : successResult.status === 'rejected'
        ? successResult.reason
        : failureResult.status === 'rejected'
          ? failureResult.reason
          : new Error('Query returned error');

  dataFreshnessManager.onFetchFailure(
    taskQueryKeys.statusCounts(projectId),
    errorReason as Error,
  );
}

interface FetchTaskStatusCountsOptions {
  projectId: string | null;
  allProjectIds?: string[];
}

function applyProjectScope(
  query: ReturnType<ReturnType<typeof getSupabaseClient>['from']>['select'],
  projectId: string | null,
  allProjectIds?: string[],
) {
  if (allProjectIds && allProjectIds.length > 0) {
    return query.in('project_id', allProjectIds);
  }
  if (projectId) {
    return query.eq('project_id', projectId);
  }
  return query;
}

async function fetchTaskStatusCounts(options: FetchTaskStatusCountsOptions): Promise<TaskStatusCountsResult> {
  const { projectId, allProjectIds } = options;
  const isAllProjects = allProjectIds && allProjectIds.length > 0;

  if (!projectId && !isAllProjects) {
    return buildEmptyTaskStatusCountsResult();
  }

  // Use projectId for freshness tracking; fall back to synthetic key for all-projects mode
  const trackingId = projectId ?? '__all-projects__';

  const visibleTaskTypes = getVisibleTaskTypes();
  const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();
  const supabase = getSupabaseClient();

  const settledResults = await Promise.allSettled([
    applyRootTaskFilter(
      applyProjectScope(
        supabase
          .from('tasks')
          .select('id', { count: 'exact', head: true }),
        projectId,
        allProjectIds,
      )
        .in('status', [...TASK_PROCESSING_STATUSES])
        .in('task_type', visibleTaskTypes),
    ),
    applyRootTaskFilter(
      applyProjectScope(
        supabase
          .from('tasks')
          .select('id', { count: 'exact', head: true }),
        projectId,
        allProjectIds,
      )
        .eq('status', 'Complete')
        .gte('generation_processed_at', oneHourAgo)
        .in('task_type', visibleTaskTypes),
    ),
    applyRootTaskFilter(
      applyProjectScope(
        supabase
          .from('tasks')
          .select('id', { count: 'exact', head: true }),
        projectId,
        allProjectIds,
      )
        .in('status', [...TASK_FAILURE_STATUSES])
        .gte('updated_at', oneHourAgo)
        .in('task_type', visibleTaskTypes),
    ),
  ]) as [
    PromiseSettledResult<{ count: number | null; error: unknown }>,
    PromiseSettledResult<{ count: number | null; error: unknown }>,
    PromiseSettledResult<{ count: number | null; error: unknown }>,
  ];

  const failedQueries: TaskStatusCountsQuery[] = [];

import { QueryClient } from '@tanstack/react-query';
import type { GenerationRow } from '@/domains/generation/types';
import { Task } from '@/types/tasks';
import { fetchTaskInProject } from '@/integrations/supabase/repositories/taskRepository';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { resolveTaskProjectScope } from '@/shared/lib/tasks/resolveTaskProjectScope';
import { getGenerationId } from '@/shared/lib/media/mediaTypeHelpers';
import {
  resolveGenerationTaskMappings,
  toGenerationTaskMappingCacheEntry,
  type GenerationTaskMappingCacheEntry,
  type GenerationTaskMappingStatus,
} from '@/shared/lib/tasks/generationTaskRepository';

interface PreloadGenerationTaskMappingsOptions {
  batchSize?: number;
  delayBetweenBatches?: number;
  preloadFullTaskData?: boolean;
}

interface GenerationWithTaskData extends GenerationRow {
  taskId?: string | null;
  taskData?: Task | null;
  taskMappingStatus?: GenerationTaskMappingStatus;
  taskMappingError?: string;
}

/** Preload cached generation -> task mappings for a batch of generations. */
export async function preloadGenerationTaskMappings(
  queryClient: QueryClient,
  generationIds: string[],
  projectId: string | null,
  options: PreloadGenerationTaskMappingsOptions = {},
) {
  const effectiveProjectId = resolveTaskProjectScope(projectId);
  const {
    batchSize = 5,
    delayBetweenBatches = 200,
    preloadFullTaskData = false,
  } = options;

  for (let i = 0; i < generationIds.length; i += batchSize) {
    const batch = generationIds.slice(i, i + batchSize);

    const mappings = await resolveGenerationTaskMappings(batch, {
      projectId: effectiveProjectId ?? undefined,
    });
    let reportedBatchQueryFailure = false;

    const prefetchTasks: Array<Promise<unknown>> = [];

    batch.forEach((generationId) => {
      const mapping = mappings.get(generationId);
      const cacheEntry = toGenerationTaskMappingCacheEntry(mapping);
      queryClient.setQueryData<GenerationTaskMappingCacheEntry>(
        taskQueryKeys.generationMapping(generationId),
        cacheEntry,
      );

      if (!reportedBatchQueryFailure && cacheEntry.status === 'query_failed' && cacheEntry.queryError) {
        reportedBatchQueryFailure = true;
        normalizeAndPresentError(new Error(cacheEntry.queryError), {
          context: 'GenerationTaskCache',
          showToast: false,
        });
      }

      if (preloadFullTaskData && effectiveProjectId && cacheEntry.taskId && cacheEntry.status === 'ok') {
        prefetchTasks.push(queryClient.prefetchQuery({
          queryKey: taskQueryKeys.single(cacheEntry.taskId, effectiveProjectId),
          queryFn: () => fetchTaskInProject(cacheEntry.taskId, effectiveProjectId),
          staleTime: 2 * 60 * 1000,
        }));
      }
    });

    if (prefetchTasks.length > 0) {
      await Promise.all(prefetchTasks);
    }

    if (i + batchSize < generationIds.length) {
      await new Promise((resolve) => setTimeout(resolve, delayBetweenBatches));
    }
  }
}

export function mergeGenerationsWithTaskData(
  generations: GenerationRow[],
  queryClient: QueryClient,
  projectId: string | null,
): GenerationWithTaskData[] {
  const effectiveProjectId = resolveTaskProjectScope(projectId);

  return generations.map((generation) => {
    const generationId = getGenerationId(generation);
    const cachedMapping = queryClient.getQueryData<GenerationTaskMappingCacheEntry>(
      taskQueryKeys.generationMapping(generationId),
    );
    const taskId = cachedMapping?.taskId || null;
    const taskData = (taskId && effectiveProjectId)
      ? queryClient.getQueryData<Task | null>(taskQueryKeys.single(taskId, effectiveProjectId))
      : null;
    const taskMappingStatus = cachedMapping?.status ?? (taskId ? 'ok' : 'not_loaded');

    return {
      ...generation,
      taskId,
      taskData,
      taskMappingStatus,
      ...(cachedMapping?.queryError ? { taskMappingError: cachedMapping.queryError } : {}),
    };
  });
}

import React, { createContext, useMemo } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { GenerationRow } from '@/domains/generation/types';
import type { Task } from '@/types/tasks';
import {
  preloadGenerationTaskMappings,
  mergeGenerationsWithTaskData,
} from '@/domains/generation/hooks/tasks/generationTaskCache';
import { getProjectSelectionFallbackId } from '@/shared/contexts/projectSelectionStore';

// ================================================================
// GENERATION-TASK INTEGRATION CONTEXT
// ================================================================
// This context provides the canonical generation -> task mapping preloader plus
// generation/task cache merging helpers used by media surfaces.

interface GenerationTaskContextValue {
  // Methods for working with generation-task mappings
  preloadTaskMappings: (generationIds: string[]) => Promise<void>;
  enhanceWithTaskData: (generations: GenerationRow[]) => (GenerationRow & { taskId?: string | null; taskData?: Task | null })[];

  // Configuration
  isPreloadingEnabled: boolean;
  setPreloadingEnabled: (enabled: boolean) => void;
}

const GenerationTaskContext = createContext<GenerationTaskContextValue | null>(null);

interface GenerationTaskProviderProps {
  children: React.ReactNode;

  // Configuration options
  enableBackgroundPreloading?: boolean;
  preloadBatchSize?: number;
  preloadDelay?: number;
}

export function GenerationTaskProvider({ 
  children, 
  enableBackgroundPreloading = true,
  preloadBatchSize = 5,
  preloadDelay = 200 
}: GenerationTaskProviderProps) {
  const queryClient = useQueryClient();
  const [isPreloadingEnabled, setPreloadingEnabled] = React.useState(enableBackgroundPreloading);

  const preloadTaskMappings = React.useCallback(async (generationIds: string[]) => {
    if (!isPreloadingEnabled || generationIds.length === 0) return;
    const projectId = getProjectSelectionFallbackId();

    try {
      await preloadGenerationTaskMappings(queryClient, generationIds, projectId, {
        batchSize: preloadBatchSize,
        delayBetweenBatches: preloadDelay,
        preloadFullTaskData: true, // Preload full task data for better UX
      });
    } catch {
      // Best effort preloading: the main UI can still function without prefetched task data.
    }
  }, [queryClient, isPreloadingEnabled, preloadBatchSize, preloadDelay]);

  const enhanceWithTaskData = React.useCallback((generations: GenerationRow[]) => {
    const projectId = getProjectSelectionFallbackId();
    return mergeGenerationsWithTaskData(generations, queryClient, projectId);
  }, [queryClient]);

  // Memoize context value to prevent unnecessary re-renders of consumers
  const contextValue = useMemo<GenerationTaskContextValue>(() => ({
    preloadTaskMappings,
    enhanceWithTaskData,
    isPreloadingEnabled,
    setPreloadingEnabled,
  }), [preloadTaskMappings, enhanceWithTaskData, isPreloadingEnabled, setPreloadingEnabled]);

  return (
    <GenerationTaskContext.Provider value={contextValue}>
      {children}
    </GenerationTaskContext.Provider>
  );
}

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { fetchTaskInProject } from '@/integrations/supabase/repositories/taskRepository';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';
import {
  getSourceTaskIdLegacyCompatible,
  hasOrchestratorDetails,
} from '@/shared/lib/taskIdHelpers';
import type { TaskDetailsData } from '../../types';

interface VariantTaskLike {
  params?: Record<string, unknown> | null;
}

interface UseVariantSourceTaskInput {
  projectId?: string | null;
  activeVariant: VariantTaskLike | null;
  taskDetailsData: TaskDetailsData | undefined;
}

export function useVariantSourceTask(input: UseVariantSourceTaskInput) {
  const { projectId, activeVariant, taskDetailsData } = input;

  const { variantSourceTaskId, variantHasOrchestratorDetails } = useMemo(() => {
    const variantParams = activeVariant?.params as Record<string, unknown> | undefined;
    return {
      variantSourceTaskId: getSourceTaskIdLegacyCompatible(variantParams),
      variantHasOrchestratorDetails: hasOrchestratorDetails(variantParams),
    };
  }, [activeVariant?.params]);

  const {
    data: variantSourceTask,
    error: variantSourceTaskQueryError,
    isLoading: isLoadingVariantTask,
  } = useQuery({
    queryKey: taskQueryKeys.single(variantSourceTaskId ?? '', projectId ?? null),
    queryFn: async () => {
      if (!variantSourceTaskId || !projectId) {
        return null;
      }

      try {
        return await fetchTaskInProject(variantSourceTaskId, projectId);
      } catch (error) {
        if (error instanceof Error) {
          throw error;
        }

        const message = (
          typeof error === 'object'
          && error !== null
          && 'message' in error
          && typeof error.message === 'string'
        )
          ? error.message
          : 'Failed to fetch source task';
        throw new Error(message);
      }
    },
    enabled: !!variantSourceTaskId
      && !!projectId
      && variantSourceTaskId !== taskDetailsData?.taskId
      && !variantHasOrchestratorDetails,
    staleTime: Infinity,
  });
  const variantSourceTaskError = useMemo(() => {
    if (!variantSourceTaskQueryError) {
      return null;
    }
    return variantSourceTaskQueryError instanceof Error
      ? variantSourceTaskQueryError
      : new Error('Failed to fetch source task');
  }, [variantSourceTaskQueryError]);

  return {
    variantSourceTaskId,
    variantHasOrchestratorDetails,
    variantSourceTask,
    variantSourceTaskError,
    isLoadingVariantTask,
  };
}

import { useEffect, useMemo, useSyncExternalStore } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { useProjectSelectionContext } from '@/shared/contexts/ProjectContext';
import { taskReferencesGeneration } from '@/shared/hooks/tasks/usePendingGenerationTasks';
import { realtimeEventProcessor } from '@/shared/realtime/RealtimeEventProcessor';
import { TASK_STATUS } from '@/types/tasks';
import type { ResolvedAssetRegistryEntry } from '@/tools/video-editor/types';

interface UseActiveTaskClipsArgs {
  registry: Record<string, ResolvedAssetRegistryEntry> | undefined;
}

interface UseActiveTaskClipsReturn {
  activeTaskAssetKeys: Set<string>;
}

interface ActiveTaskRow {
  id: string;
  status: string;
  task_type: string;
  params: Record<string, unknown> | null;
}

const ACTIVE_TASK_CLIPS_QUERY_KEY = 'active-task-clips';
const OPTIMISTIC_TIMEOUT_MS = 8000;

const optimisticListeners = new Set<() => void>();
const optimisticTimeouts = new Map<string, ReturnType<typeof setTimeout>>();
let optimisticActiveAssetKeysSnapshot = new Set<string>();

function activeTaskClipsQueryKey(projectId: string | null) {
  return [ACTIVE_TASK_CLIPS_QUERY_KEY, projectId ?? '__no-project__'] as const;
}

function emitOptimisticChange() {
  optimisticListeners.forEach((listener) => listener());
}

function subscribeOptimisticActive(listener: () => void) {
  optimisticListeners.add(listener);
  return () => optimisticListeners.delete(listener);
}

function getOptimisticActiveSnapshot() {
  return optimisticActiveAssetKeysSnapshot;
}

function removeOptimisticActive(assetKeys: Iterable<string>) {
  let nextSnapshot: Set<string> | null = null;

  for (const assetKey of assetKeys) {
    if (!optimisticActiveAssetKeysSnapshot.has(assetKey)) {
      continue;
    }

    if (!nextSnapshot) {
      nextSnapshot = new Set(optimisticActiveAssetKeysSnapshot);
    }

    nextSnapshot.delete(assetKey);

    const timeout = optimisticTimeouts.get(assetKey);
    if (timeout) {
      clearTimeout(timeout);
      optimisticTimeouts.delete(assetKey);
    }
  }

  if (!nextSnapshot) {
    return;
  }

  optimisticActiveAssetKeysSnapshot = nextSnapshot;
  emitOptimisticChange();
}

function scheduleOptimisticExpiry(assetKey: string) {
  const existingTimeout = optimisticTimeouts.get(assetKey);
  if (existingTimeout) {
    clearTimeout(existingTimeout);
  }

  const timeout = setTimeout(() => {
    optimisticTimeouts.delete(assetKey);

    if (!optimisticActiveAssetKeysSnapshot.has(assetKey)) {
      return;
    }

    const nextSnapshot = new Set(optimisticActiveAssetKeysSnapshot);
    nextSnapshot.delete(assetKey);
    optimisticActiveAssetKeysSnapshot = nextSnapshot;
    emitOptimisticChange();
  }, OPTIMISTIC_TIMEOUT_MS);

  optimisticTimeouts.set(assetKey, timeout);
}

export function addOptimisticActive(assetKeys: string[]) {
  let nextSnapshot: Set<string> | null = null;

  for (const assetKey of assetKeys) {
    if (!assetKey) {
      continue;
    }

    if (!optimisticActiveAssetKeysSnapshot.has(assetKey)) {
      if (!nextSnapshot) {
        nextSnapshot = new Set(optimisticActiveAssetKeysSnapshot);
      }
      nextSnapshot.add(assetKey);
    }

    scheduleOptimisticExpiry(assetKey);
  }

  if (!nextSnapshot) {
    return;
  }

  optimisticActiveAssetKeysSnapshot = nextSnapshot;
  emitOptimisticChange();
}

async function fetchActiveTasks(projectId: string): Promise<ActiveTaskRow[]> {
  const { getSupabaseClient } = await import('@/integrations/supabase/client');
  const { data, error } = await getSupabaseClient()
    .from('tasks')
    .select('id, status, task_type, params')
    .eq('project_id', projectId)
    .in('status', [TASK_STATUS.QUEUED, TASK_STATUS.IN_PROGRESS]);

  if (error) {
    throw error;
  }

  return (data ?? []).map((task) => ({
    id: task.id,
    status: task.status,
    task_type: task.task_type,
    params: task.params as Record<string, unknown> | null,
  }));
}

export function useActiveTaskClips({ registry }: UseActiveTaskClipsArgs): UseActiveTaskClipsReturn {
  const { selectedProjectId } = useProjectSelectionContext();
  const queryClient = useQueryClient();
  const optimisticActiveAssetKeys = useSyncExternalStore(
    subscribeOptimisticActive,
    getOptimisticActiveSnapshot,
    getOptimisticActiveSnapshot
  );

  const generationAssetMap = useMemo(() => {
    const map = new Map<string, string[]>();

    if (!registry) {
      return map;
    }

    for (const [assetKey, entry] of Object.entries(registry)) {
      if (!entry.generationId) {
        continue;
      }

      const assetKeys = map.get(entry.generationId);
      if (assetKeys) {
        assetKeys.push(assetKey);
      } else {
        map.set(entry.generationId, [assetKey]);
      }
    }

    return map;
  }, [registry]);

  const { data: activeTasks = [] } = useQuery({
    queryKey: activeTaskClipsQueryKey(selectedProjectId),
    queryFn: async () => {
      if (!selectedProjectId) {
        return [];
      }

      return fetchActiveTasks(selectedProjectId);
    },
    enabled: !!selectedProjectId,
    refetchInterval: 5000,
    staleTime: 0,
    gcTime: 10000,
    refetchOnWindowFocus: 'always',
  });

  const queriedActiveAssetKeys = useMemo(() => {
    const activeAssetKeys = new Set<string>();

    if (generationAssetMap.size === 0 || activeTasks.length === 0) {
      return activeAssetKeys;
    }

    for (const task of activeTasks) {
      for (const [generationId, assetKeys] of generationAssetMap.entries()) {
        if (!taskReferencesGeneration(task.params, generationId)) {
          continue;
        }

        assetKeys.forEach((assetKey) => activeAssetKeys.add(assetKey));
      }
    }

    return activeAssetKeys;
  }, [activeTasks, generationAssetMap]);

  useEffect(() => {
    if (queriedActiveAssetKeys.size === 0) {
      return;
    }

    removeOptimisticActive(queriedActiveAssetKeys);
  }, [queriedActiveAssetKeys]);

  useEffect(() => {
    if (!selectedProjectId) {
      return;
    }

    return realtimeEventProcessor.onEvent((event) => {
      if (event.type === 'tasks-created') {
        const projectMatch = event.tasks.some((task) => task.projectId === selectedProjectId);
        if (projectMatch) {
          void queryClient.invalidateQueries({ queryKey: activeTaskClipsQueryKey(selectedProjectId) });
        }
        return;
      }

      if (event.type === 'tasks-updated') {
        const projectMatch = event.tasks.some((task) => task.projectId === selectedProjectId);
        if (projectMatch) {
          void queryClient.invalidateQueries({ queryKey: activeTaskClipsQueryKey(selectedProjectId) });
        }
      }
    });
  }, [queryClient, selectedProjectId]);

  const activeTaskAssetKeys = useMemo(() => {
    if (queriedActiveAssetKeys.size === 0) {
      return optimisticActiveAssetKeys;
    }

    if (optimisticActiveAssetKeys.size === 0) {
      return queriedActiveAssetKeys;
    }

    const next = new Set(queriedActiveAssetKeys);
    optimisticActiveAssetKeys.forEach((assetKey) => next.add(assetKey));
    return next;
  }, [optimisticActiveAssetKeys, queriedActiveAssetKeys]);

  return {
    activeTaskAssetKeys,
  };

import type { Json } from '@/integrations/supabase/jsonTypes';
import type { Task } from '@/types/tasks';

export interface TaskDbRow {
  id: string;
  task_type: string;
  params: Json | null;
  status: Task['status'];
  dependant_on?: string[] | null;
  output_location?: string | null;
  created_at: string;
  updated_at?: string | null;
  project_id: string;
  cost_cents?: number | null;
  generation_started_at?: string | null;
  generation_processed_at?: string | null;
  error_message?: string | null;
}

function isStringOrNull(value: unknown): value is string | null {
  return value === null || typeof value === 'string';
}

function isStringArrayOrNull(value: unknown): value is string[] | null {
  return value === null || (Array.isArray(value) && value.every((item) => typeof item === 'string'));
}

export function isTaskDbRow(value: unknown): value is TaskDbRow {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return false;
  }

  const row = value as Record<string, unknown>;

  if (
    typeof row.id !== 'string'
    || typeof row.task_type !== 'string'
    || typeof row.status !== 'string'
    || typeof row.created_at !== 'string'
    || typeof row.project_id !== 'string'
  ) {
    return false;
  }

  if (row.updated_at !== undefined && !isStringOrNull(row.updated_at)) return false;
  if (row.output_location !== undefined && !isStringOrNull(row.output_location)) return false;
  if (row.error_message !== undefined && !isStringOrNull(row.error_message)) return false;
  if (row.generation_started_at !== undefined && !isStringOrNull(row.generation_started_at)) return false;
  if (row.generation_processed_at !== undefined && !isStringOrNull(row.generation_processed_at)) return false;
  if (row.cost_cents !== undefined && row.cost_cents !== null && typeof row.cost_cents !== 'number') return false;
  if (row.dependant_on !== undefined && !isStringArrayOrNull(row.dependant_on)) return false;

  return true;
}

function mapTaskParams(params: Json | null): Record<string, unknown> {
  return (params && typeof params === 'object' && !Array.isArray(params))
    ? (params as Record<string, unknown>)
    : {};
}

export function mapTaskDbRowToTask(row: TaskDbRow): Task {
  return {
    id: row.id,
    taskType: row.task_type,
    params: mapTaskParams(row.params),
    status: row.status,
    dependantOn: row.dependant_on ?? undefined,
    outputLocation: row.output_location ?? undefined,
    createdAt: row.created_at,
    updatedAt: row.updated_at ?? undefined,
    projectId: row.project_id,
    costCents: row.cost_cents ?? undefined,
    generationStartedAt: row.generation_started_at ?? undefined,
    generationProcessedAt: row.generation_processed_at ?? undefined,
    errorMessage: row.error_message ?? undefined,
  };
}

