/**
 * RealtimeProvider - Manages realtime connection and provides status to the app
 *
 * This provider:
 * 1. Connects to the realtime service when a project is selected
 * 2. Wires raw events from connection → processor → invalidation
 * 3. Exposes connection status to the component tree
 *
 */

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo } from 'react';
import { useProject } from '@/shared/contexts/ProjectContext';
import { getRealtimeConnection } from '@/shared/realtime/RealtimeConnection';
import { realtimeEventProcessor } from '@/shared/realtime/RealtimeEventProcessor';
import { dataFreshnessManager } from '@/shared/realtime/DataFreshnessManager';
import { useRealtimeInvalidation } from '@/shared/hooks/useRealtimeInvalidation';
import type { ConnectionState, ConnectionStatus } from '@/shared/realtime/types';

// =============================================================================
// Context
// =============================================================================

interface RealtimeContextValue {
  /** Current connection status */
  status: ConnectionStatus;
  /** Whether currently connected */
  isConnected: boolean;
  /** Whether connection is in progress */
  isConnecting: boolean;
  /** Whether in a failed state (exhausted retries) */
  isFailed: boolean;
  /** Error message if any */
  error: string | null;
  /** Current reconnect attempt (0 if not reconnecting) */
  reconnectAttempt: number;
  /** Manually trigger reconnection */
  reconnect: () => void;
}

const RealtimeContext = createContext<RealtimeContextValue>({
  status: 'disconnected',
  isConnected: false,
  isConnecting: false,
  isFailed: false,
  error: null,
  reconnectAttempt: 0,
  reconnect: () => {},
});

export const useRealtime = () => useContext(RealtimeContext);

// =============================================================================
// Provider
// =============================================================================

interface RealtimeProviderProps {
  children: React.ReactNode;
}

export function RealtimeProvider({ children }: RealtimeProviderProps) {
  const { selectedProjectId } = useProject();
  const realtimeConnection = useMemo(() => getRealtimeConnection(), []);
  const [connectionState, setConnectionState] = useState<ConnectionState>(() =>
    realtimeConnection.getState()
  );

  // Set up the invalidation hook (subscribes to processed events)
  useRealtimeInvalidation();

  // Wire connection events → processor
  useEffect(() => {
    const unsubscribe = realtimeConnection.onEvent((event) => {
      realtimeEventProcessor.process(event);
    });
    return unsubscribe;
  }, [realtimeConnection]);

  // Subscribe to connection status changes
  useEffect(() => {
    const unsubscribe = realtimeConnection.onStatusChange((state) => {
      setConnectionState(state);
    });
    return unsubscribe;
  }, [realtimeConnection]);

  // Connect/disconnect when project changes
  useEffect(() => {
    if (!selectedProjectId) {
      realtimeConnection.disconnect();
      dataFreshnessManager.reset();
      return;
    }

    realtimeConnection.connect(selectedProjectId);

    return () => {
      // Don't disconnect on cleanup - let the next effect handle it
      // This prevents disconnect/reconnect when the component re-renders
    };
  }, [selectedProjectId, realtimeConnection]);

  // Clean up on unmount
  useEffect(() => {
    return () => {
      realtimeEventProcessor.clear();
    };
  }, []);

  // Manual reconnect function
  const reconnect = useCallback(() => {
    if (selectedProjectId) {
      realtimeConnection.reset();
      realtimeConnection.connect(selectedProjectId);
    }
  }, [selectedProjectId, realtimeConnection]);

  // Derive context value from connection state
  const contextValue: RealtimeContextValue = {
    status: connectionState.status,
    isConnected: connectionState.status === 'connected',
    isConnecting: connectionState.status === 'connecting',
    isFailed: connectionState.status === 'failed',
    error: connectionState.error,
    reconnectAttempt: connectionState.reconnectAttempt,
    reconnect,
  };

  return (
    <RealtimeContext.Provider value={contextValue}>
      {children}
    </RealtimeContext.Provider>
  );
}

import { shallow } from 'zustand/shallow';
import { useStoreWithEqualityFn } from 'zustand/traditional';
import { createStore } from 'zustand/vanilla';
import { mapTaskDbRowToTask, isTaskDbRow } from '@/shared/lib/taskRowMapper';
import { resolveTaskProjectScope } from '@/shared/lib/tasks/resolveTaskProjectScope';
import { deepEqual } from '@/shared/lib/utils/deepEqual';
import { TASK_STATUS, type Task } from '@/types/tasks';

export interface PendingGenerationTaskSnapshot {
  id: string;
  status: Task['status'];
  task_type: Task['taskType'];
}

interface RealtimeTaskScopeState {
  tasks: Record<string, Task>;
  taskGenerationIds: Record<string, readonly string[]>;
  pendingTaskIdsByGeneration: Record<string, readonly string[]>;
  pendingTasksByGeneration: Record<string, readonly PendingGenerationTaskSnapshot[]>;
}

interface RealtimeStoreState {
  scopes: Record<string, RealtimeTaskScopeState>;
  upsertTask: (task: Task, projectId?: string | null) => Task | null;
  upsertTasks: (tasks: readonly Task[], projectId?: string | null) => Task[];
  resetScope: (projectId?: string | null) => void;
  resetAll: () => void;
}

const EMPTY_TASKS = Object.freeze({}) as Record<string, Task>;
const EMPTY_GENERATION_IDS = Object.freeze({}) as Record<string, readonly string[]>;
const EMPTY_PENDING_IDS = Object.freeze({}) as Record<string, readonly string[]>;
const EMPTY_PENDING_TASKS = Object.freeze({}) as Record<string, readonly PendingGenerationTaskSnapshot[]>;
const EMPTY_STRING_ARRAY = Object.freeze([]) as readonly string[];
const EMPTY_PENDING_TASK_ARRAY = Object.freeze([]) as readonly PendingGenerationTaskSnapshot[];

function createEmptyScopeState(): RealtimeTaskScopeState {
  return {
    tasks: EMPTY_TASKS,
    taskGenerationIds: EMPTY_GENERATION_IDS,
    pendingTaskIdsByGeneration: EMPTY_PENDING_IDS,
    pendingTasksByGeneration: EMPTY_PENDING_TASKS,
  };
}

function isPendingTaskStatus(status: Task['status']): boolean {
  return status === TASK_STATUS.QUEUED || status === TASK_STATUS.IN_PROGRESS;
}

function addGenerationId(target: Set<string>, value: unknown): void {
  if (typeof value !== 'string') {
    return;
  }

  const trimmed = value.trim();
  if (trimmed) {
    target.add(trimmed);
  }
}

function addGenerationIdsFromArray(target: Set<string>, value: unknown): void {
  if (!Array.isArray(value)) {
    return;
  }

  value.forEach((item) => addGenerationId(target, item));
}

function addGenerationIdsFromRecord(target: Set<string>, value: unknown): void {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return;
  }

  const record = value as Record<string, unknown>;
  addGenerationId(target, record.based_on);
  addGenerationId(target, record.source_generation_id);
  addGenerationId(target, record.generation_id);
  addGenerationId(target, record.input_generation_id);
  addGenerationId(target, record.parent_generation_id);
  addGenerationId(target, record.start_image_generation_id);
  addGenerationId(target, record.end_image_generation_id);
  addGenerationId(target, record.pair_shot_generation_id);
  addGenerationIdsFromArray(target, record.input_image_generation_ids);
  addGenerationIdsFromArray(target, record.pair_shot_generation_ids);
}

export function collectTaskGenerationIds(task: Task): readonly string[] {
  if (!isPendingTaskStatus(task.status)) {
    return EMPTY_STRING_ARRAY;
  }

  const generationIds = new Set<string>();
  addGenerationIdsFromRecord(generationIds, task.params);

  const params = task.params as Record<string, unknown>;
  addGenerationIdsFromRecord(generationIds, params.orchestrator_details);
  addGenerationIdsFromRecord(generationIds, params.full_orchestrator_payload);
  addGenerationIdsFromRecord(generationIds, params.individual_segment_params);

  if (generationIds.size === 0) {
    return EMPTY_STRING_ARRAY;
  }

  return Object.freeze(Array.from(generationIds));
}

function areStringArraysEqual(left: readonly string[], right: readonly string[]): boolean {
  if (left === right) {
    return true;
  }

  if (left.length !== right.length) {
    return false;
  }

  for (let index = 0; index < left.length; index += 1) {
    if (left[index] !== right[index]) {
      return false;
    }
  }

  return true;
}

function buildPendingTaskSummaries(
  taskIds: readonly string[],
  tasks: Record<string, Task>,
  previous: readonly PendingGenerationTaskSnapshot[],
): readonly PendingGenerationTaskSnapshot[] {
  if (taskIds.length === 0) {
    return EMPTY_PENDING_TASK_ARRAY;
  }

  const previousById = new Map(previous.map((task) => [task.id, task]));
  const next = taskIds.flatMap((taskId) => {
    const task = tasks[taskId];
    if (!task || !isPendingTaskStatus(task.status)) {
      return [];
    }

    const existing = previousById.get(task.id);
    if (existing && existing.status === task.status && existing.task_type === task.taskType) {
      return [existing];
    }

    return [{
      id: task.id,
      status: task.status,
      task_type: task.taskType,
    }];
  });

  if (next.length === 0) {
    return EMPTY_PENDING_TASK_ARRAY;
  }

  if (next.length === previous.length && next.every((task, index) => task === previous[index])) {
    return previous;
  }

  return Object.freeze(next);
}

function resolveScopeKey(projectId?: string | null): string | null {
  return resolveTaskProjectScope(projectId);
}

function resolveTaskScopeKey(task: Task, projectId?: string | null): string | null {
  return resolveTaskProjectScope(projectId ?? task.projectId);
}

function getScopeState(
  scopes: Record<string, RealtimeTaskScopeState>,
  scopeKey: string,
): RealtimeTaskScopeState {
  return scopes[scopeKey] ?? createEmptyScopeState();
}

function buildUpdatedScopeState(scopeState: RealtimeTaskScopeState, task: Task): RealtimeTaskScopeState {
  const previousTask = scopeState.tasks[task.id];
  const nextTask = previousTask && deepEqual(previousTask, task) ? previousTask : task;
  const previousGenerationIds = scopeState.taskGenerationIds[task.id] ?? EMPTY_STRING_ARRAY;
  const nextGenerationIds = collectTaskGenerationIds(nextTask);
  const taskChanged = previousTask !== nextTask;
  const generationIdsChanged = !areStringArraysEqual(previousGenerationIds, nextGenerationIds);

  if (!taskChanged && !generationIdsChanged) {
    return scopeState;
  }

  const nextTasks = taskChanged
    ? { ...scopeState.tasks, [task.id]: nextTask }
    : scopeState.tasks;

  const nextTaskGenerationIds = { ...scopeState.taskGenerationIds };
  if (nextGenerationIds.length > 0) {
    nextTaskGenerationIds[task.id] = nextGenerationIds;
  } else {
    delete nextTaskGenerationIds[task.id];
  }

  const nextPendingTaskIdsByGeneration = { ...scopeState.pendingTaskIdsByGeneration };
  const nextPendingTasksByGeneration = { ...scopeState.pendingTasksByGeneration };

  const affectedGenerationIds = new Set<string>([
    ...previousGenerationIds,
    ...nextGenerationIds,
  ]);

  affectedGenerationIds.forEach((generationId) => {
    const previousTaskIds = scopeState.pendingTaskIdsByGeneration[generationId] ?? EMPTY_STRING_ARRAY;
    const shouldInclude = nextGenerationIds.includes(generationId);
    const alreadyIncluded = previousTaskIds.includes(task.id);

    let nextTaskIds = previousTaskIds;
    if (shouldInclude && !alreadyIncluded) {
      nextTaskIds = Object.freeze([...previousTaskIds, task.id]);
    } else if (!shouldInclude && alreadyIncluded) {
      nextTaskIds = Object.freeze(previousTaskIds.filter((pendingTaskId) => pendingTaskId !== task.id));
    }

    if (nextTaskIds.length === 0) {
      delete nextPendingTaskIdsByGeneration[generationId];
    } else {
      nextPendingTaskIdsByGeneration[generationId] = nextTaskIds;
    }

    const previousPendingTasks = scopeState.pendingTasksByGeneration[generationId] ?? EMPTY_PENDING_TASK_ARRAY;
    const nextPendingTasks = buildPendingTaskSummaries(nextTaskIds, nextTasks, previousPendingTasks);

    if (nextPendingTasks.length === 0) {
      delete nextPendingTasksByGeneration[generationId];
    } else {
      nextPendingTasksByGeneration[generationId] = nextPendingTasks;
    }
  });

  return {
    tasks: nextTasks,
    taskGenerationIds: nextTaskGenerationIds,
    pendingTaskIdsByGeneration: nextPendingTaskIdsByGeneration,
    pendingTasksByGeneration: nextPendingTasksByGeneration,
  };
}

function upsertTaskIntoScopes(
  scopes: Record<string, RealtimeTaskScopeState>,
  task: Task,
  projectId?: string | null,
): Record<string, RealtimeTaskScopeState> {
  const scopeKey = resolveTaskScopeKey(task, projectId);
  if (!scopeKey) {
    return scopes;
  }

  const scopeState = getScopeState(scopes, scopeKey);
  const nextScopeState = buildUpdatedScopeState(scopeState, task);
  if (nextScopeState === scopeState) {
    return scopes;
  }

  return {
    ...scopes,
    [scopeKey]: nextScopeState,
  };
}

const realtimeTaskStore = createStore<RealtimeStoreState>((set, get) => ({
  scopes: {},
  upsertTask: (task, projectId) => {
    const scopeKey = resolveTaskScopeKey(task, projectId);
    if (!scopeKey) {
      return null;
    }

    set((state) => ({
      scopes: upsertTaskIntoScopes(state.scopes, task, projectId),
    }));

    return get().scopes[scopeKey]?.tasks[task.id] ?? null;
  },
  upsertTasks: (tasks, projectId) => {
    if (tasks.length === 0) {
      return [];
    }

    set((state) => {
      let nextScopes = state.scopes;
      tasks.forEach((task) => {
        nextScopes = upsertTaskIntoScopes(nextScopes, task, projectId);
      });

      return nextScopes === state.scopes
        ? state
        : { scopes: nextScopes };
    });

    return tasks.flatMap((task) => {
      const scopeKey = resolveTaskScopeKey(task, projectId);
      if (!scopeKey) {
        return [];
      }

      const seededTask = get().scopes[scopeKey]?.tasks[task.id];
      return seededTask ? [seededTask] : [];
    });
  },
  resetScope: (projectId) => {
    const scopeKey = resolveScopeKey(projectId);
    if (!scopeKey) {
      return;
    }

    set((state) => {
      if (!(scopeKey in state.scopes)) {
        return state;
      }

      const nextScopes = { ...state.scopes };
      delete nextScopes[scopeKey];

/**
 * RealtimeConnection - Manages Supabase WebSocket connection lifecycle
 *
 * Single responsibility: Connect, reconnect, and emit connection status changes.
 * Does NOT filter events or make business decisions about what to invalidate.
 *
 * State machine: disconnected → connecting → connected ↔ reconnecting → failed
 */
import { RealtimeChannel } from '@supabase/supabase-js';
import { getSupabaseClient } from '@/integrations/supabase/client';
import { dataFreshnessManager } from './DataFreshnessManager';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { listenAppEvent } from '@/shared/lib/typedEvents';
import {
  ConnectionState,
  ConnectionStatusCallback,
  RawDatabaseEvent,
  DatabaseTable,
  DatabaseEventType,
  RealtimeConfig,
  DEFAULT_REALTIME_CONFIG,
  INITIAL_CONNECTION_STATE
} from './types';
type RawEventCallback = (event: RawDatabaseEvent) => void;
export class RealtimeConnection {
  private channel: RealtimeChannel | null = null;
  private state: ConnectionState = { ...INITIAL_CONNECTION_STATE };
  private config: RealtimeConfig;
  private reconnectTimeout: NodeJS.Timeout | null = null;
  private subscribeTimeout: NodeJS.Timeout | null = null;
  private statusCallbacks = new Set<ConnectionStatusCallback>();
  private eventCallbacks = new Set<RawEventCallback>();
  private unsubAuthHeal: (() => void) | null = null;
  private activeConnectSequence = 0;
  private connectInFlight: Promise<boolean> | null = null;
  private connectInFlightProjectId: string | null = null;
  constructor(config: Partial<RealtimeConfig> = {}) {
    this.config = { ...DEFAULT_REALTIME_CONFIG, ...config };
    if (typeof window !== 'undefined') {
      this.unsubAuthHeal = listenAppEvent('realtime:auth-heal', () => this.handleAuthHeal());
    }
  }
  /**
   * Connect to a project's realtime channel.
   * If already connected to a different project, disconnects first.
   */
  async connect(projectId: string): Promise<boolean> {
    if (this.state.projectId === projectId && this.state.status === 'connected') {
      return true;
    }
    if (this.state.projectId && this.state.projectId !== projectId) {
      await this.disconnect();
    }
    return this.startConnect(projectId);
  }
  /**
   * Disconnect from the current project.
   */
  async disconnect(): Promise<void> {
    this.activeConnectSequence += 1;
    this.connectInFlight = null;
    this.connectInFlightProjectId = null;
    this.clearTimeouts();
    if (this.channel) {
      try {
        await this.channel.unsubscribe();
      } catch {
      }
      this.channel = null;
    }
    this.setState({
      status: 'disconnected',
      projectId: null,
      error: null,
      reconnectAttempt: 0,
      nextRetryAt: null,
    });
    dataFreshnessManager.onRealtimeStatusChange('disconnected', 'Disconnected');
  }
  /**
   * Get current connection state.
   */
  getState(): Readonly<ConnectionState> {
    return { ...this.state };
  }
  /**
   * Subscribe to connection status changes.
   */
  onStatusChange(callback: ConnectionStatusCallback): () => void {
    this.statusCallbacks.add(callback);
    callback(this.getState());
    return () => this.statusCallbacks.delete(callback);
  }
  /**
   * Subscribe to raw database events.
   */
  onEvent(callback: RawEventCallback): () => void {
    this.eventCallbacks.add(callback);
    return () => this.eventCallbacks.delete(callback);
  }
  /**
   * Reset connection state (useful for testing or forced reconnect).
   */
  reset(): void {
    this.activeConnectSequence += 1;
    this.connectInFlight = null;
    this.connectInFlightProjectId = null;
    this.clearTimeouts();
    this.state = { ...INITIAL_CONNECTION_STATE };
  }
  /**
   * Clean up resources.
   */
  destroy(): void {
    this.unsubAuthHeal?.();
    this.unsubAuthHeal = null;
    this.disconnect();
    this.statusCallbacks.clear();
    this.eventCallbacks.clear();
  }
  private startConnect(projectId: string): Promise<boolean> {
    if (this.connectInFlight && this.connectInFlightProjectId === projectId) {
      return this.connectInFlight;
    }
    this.clearTimeouts();
    const connectSequence = this.activeConnectSequence + 1;
    this.activeConnectSequence = connectSequence;
    const connectPromise = this.doConnect(projectId, connectSequence);
    this.connectInFlight = connectPromise;
    this.connectInFlightProjectId = projectId;
    void connectPromise.finally(() => {
      if (this.connectInFlight === connectPromise) {
        this.connectInFlight = null;
        this.connectInFlightProjectId = null;
      }
    });
    return connectPromise;
  }
  private isCurrentConnectAttempt(connectSequence: number): boolean {
    return connectSequence === this.activeConnectSequence;
  }
  private async doConnect(projectId: string, connectSequence: number): Promise<boolean> {
    if (!this.isCurrentConnectAttempt(connectSequence)) {
      return false;
    }
    this.setState({
      status: 'connecting',
      projectId,
      error: null,
      reconnectAttempt: 0,
      nextRetryAt: null,
    });
    try {
      const { data: { session }, error: sessionError } = await getSupabaseClient().auth.getSession();
      if (sessionError || !session?.user) {
        const errorMsg = sessionError?.message || 'No valid session';
        normalizeAndPresentError(new Error(errorMsg), {
          context: 'RealtimeConnection.authCheck',
          showToast: false,
          logData: {
            hasSession: !!session,
            hasUser: !!session?.user,
          },
        });
        this.setState({
          status: 'failed',
          error: errorMsg,
        });
        dataFreshnessManager.onRealtimeStatusChange('error', errorMsg);
        return false;
      }
      if (session.access_token) {
        getSupabaseClient().realtime.setAuth(session.access_token);
      }
    } catch (error) {
      const errorMsg = error instanceof Error ? error.message : 'Auth check failed';
      normalizeAndPresentError(error, {
        context: 'RealtimeConnection.authSessionFetch',
        showToast: false,
      });
      this.setState({
        status: 'failed',
        error: errorMsg,
      });
      dataFreshnessManager.onRealtimeStatusChange('error', errorMsg);
      return false;
    }
    if (!this.isCurrentConnectAttempt(connectSequence)) {
      return false;
    }
    const topic = `task-updates:${projectId}`;
    const channel = getSupabaseClient().channel(topic);
    if (!this.isCurrentConnectAttempt(connectSequence)) {
      void channel.unsubscribe().catch(() => {
      });
      return false;
    }
    this.channel = channel;
    this.setupEventHandlers(projectId, channel);
    return new Promise((resolve) => {
      let settled = false;
      const settle = (result: boolean) => {
        if (settled) {
          return;
        }
        settled = true;
        resolve(result);
      };
      const subscribeTimeout = setTimeout(() => {
        if (this.subscribeTimeout === subscribeTimeout) {
          this.subscribeTimeout = null;
        }
        if (!this.isCurrentConnectAttempt(connectSequence)) {
          settle(false);
          return;
        }
        this.handleSubscribeFailure('Timeout', projectId, connectSequence);
        settle(false);
      }, this.config.subscribeTimeout);
      this.subscribeTimeout = subscribeTimeout;
      channel.subscribe((status: string) => {
        if (!this.isCurrentConnectAttempt(connectSequence)) {
          void channel.unsubscribe().catch(() => {
          });
          return;
        }
        if (this.subscribeTimeout === subscribeTimeout) {
          clearTimeout(subscribeTimeout);
          this.subscribeTimeout = null;
        }
        if (status === 'SUBSCRIBED') {
          this.setState({
            status: 'connected',
            error: null,
            reconnectAttempt: 0,
            nextRetryAt: null,
          });
          dataFreshnessManager.onRealtimeStatusChange('connected', 'Connected');
          settle(true);
        } else if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') {
          this.handleSubscribeFailure(status, projectId, connectSequence);
          settle(false);
        }
      });
    });
  }
  private setupEventHandlers(projectId: string, channel: RealtimeChannel): void {
    channel
      .on('postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'tasks', filter: `project_id=eq.${projectId}` },
        (payload) => this.emitEvent('tasks', 'INSERT', payload.new, null)
      )
      .on('postgres_changes',
        { event: 'UPDATE', schema: 'public', table: 'tasks', filter: `project_id=eq.${projectId}` },
        (payload) => this.emitEvent('tasks', 'UPDATE', payload.new, payload.old)
      );
    channel
      .on('postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'generations', filter: `project_id=eq.${projectId}` },
        (payload) => this.emitEvent('generations', 'INSERT', payload.new, null)

/**
 * RealtimeEventProcessor - Batches and normalizes raw database events
 *
 * Single responsibility: Take raw events, batch them within a time window,
 * and emit processed events with normalized shapes.
 *
 * Does NOT make business decisions about what to invalidate - that's the
 * React layer's job.
 */

import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import {
  RawDatabaseEvent,
  ProcessedEvent,
  ProcessedEventCallback,
  TasksUpdatedEvent,
  TasksCreatedEvent,
  GenerationsInsertedEvent,
  GenerationsUpdatedEvent,
  GenerationsDeletedEvent,
  ShotGenerationsChangedEvent,
  VariantsChangedEvent,
  VariantsDeletedEvent,
  TimelinesUpdatedEvent,
  TaskRecord,
  GenerationRecord,
  ShotGenerationRecord,
  VariantRecord,
  TimelineRecord,
  RealtimeConfig,
  DEFAULT_REALTIME_CONFIG,
} from './types';

type EventQueue = Map<string, RawDatabaseEvent[]>;

export class RealtimeEventProcessor {
  private config: RealtimeConfig;
  private queue: EventQueue = new Map();
  private batchTimeout: NodeJS.Timeout | null = null;
  private callbacks = new Set<ProcessedEventCallback>();

  constructor(config: Partial<RealtimeConfig> = {}) {
    this.config = { ...DEFAULT_REALTIME_CONFIG, ...config };
  }

  // ===========================================================================
  // Public API
  // ===========================================================================

  /**
   * Process a raw database event. Events are batched and emitted after
   * the batch window expires.
   */
  process(event: RawDatabaseEvent): void {
    const key = this.getQueueKey(event);
    const existing = this.queue.get(key) || [];
    existing.push(event);
    this.queue.set(key, existing);

    // Reset batch timer
    if (this.batchTimeout) {
      clearTimeout(this.batchTimeout);
    }

    this.batchTimeout = setTimeout(() => {
      this.flush();
    }, this.config.batchWindowMs);
  }

  /**
   * Subscribe to processed events.
   */
  onEvent(callback: ProcessedEventCallback): () => void {
    this.callbacks.add(callback);
    return () => this.callbacks.delete(callback);
  }

  /**
   * Flush any pending batched events immediately.
   */
  flush(): void {
    if (this.batchTimeout) {
      clearTimeout(this.batchTimeout);
      this.batchTimeout = null;
    }

    if (this.queue.size === 0) return;

    const now = Date.now();

    // Process each queue
    this.queue.forEach((events, key) => {
      const processed = this.processQueue(key, events, now);
      if (processed) {
        this.emit(processed);
      }
    });

    this.queue.clear();
  }

  /**
   * Clear pending events without emitting.
   */
  clear(): void {
    if (this.batchTimeout) {
      clearTimeout(this.batchTimeout);
      this.batchTimeout = null;
    }
    this.queue.clear();
  }

  /**
   * Clean up resources.
   */
  destroy(): void {
    this.clear();
    this.callbacks.clear();
  }

  // ===========================================================================
  // Private: Queue Processing
  // ===========================================================================

  private getQueueKey(event: RawDatabaseEvent): string {
    // Group by table and event type
    return `${event.table}:${event.eventType}`;
  }

  private processQueue(
    key: string,
    events: RawDatabaseEvent[],
    processedAt: number
  ): ProcessedEvent | null {
    const [table, eventType] = key.split(':') as [string, string];

    switch (table) {
      case 'tasks':
        return eventType === 'INSERT'
          ? this.processTaskInserts(events, processedAt)
          : this.processTaskUpdates(events, processedAt);

      case 'generations':
        if (eventType === 'INSERT') {
          return this.processGenerationInserts(events, processedAt);
        } else if (eventType === 'DELETE') {
          return this.processGenerationDeletes(events, processedAt);
        } else {
          return this.processGenerationUpdates(events, processedAt);
        }

      case 'shot_generations':
        return this.processShotGenerationChanges(events, processedAt);

      case 'generation_variants':
        if (eventType === 'DELETE') {
          return this.processVariantDeletes(events, processedAt);
        } else {
          return this.processVariantChanges(events, processedAt);
        }

      case 'timelines':
        return this.processTimelineUpdates(events, processedAt);

      default:
        return null;
    }
  }

  // ===========================================================================
  // Private: Task Processing
  // ===========================================================================

  private processTaskInserts(
    events: RawDatabaseEvent[],
    processedAt: number
  ): TasksCreatedEvent {
    const tasks = events.map((e) => {
      const record = e.new as unknown as TaskRecord;
      return {
        id: record.id,
        taskType: record.task_type,
        projectId: record.project_id,
      };
    });

    return {
      type: 'tasks-created',
      batchSize: events.length,
      processedAt,
      tasks,
    };
  }

  private processTaskUpdates(
    events: RawDatabaseEvent[],
    processedAt: number
  ): TasksUpdatedEvent {
    const tasks = events.map((e) => {
      const newRecord = e.new as unknown as TaskRecord;
      const oldRecord = e.old as Partial<TaskRecord> | null;

      // Extract shot ID from various possible locations
      const shotId = this.extractShotIdFromTask(newRecord);

      return {
        id: newRecord.id,
        projectId: newRecord.project_id,
        newStatus: newRecord.status,
        oldStatus: oldRecord?.status,
        isComplete: newRecord.status === 'Complete',
        isFailed: newRecord.status === 'Failed' || newRecord.status === 'Cancelled',
        shotId,
      };
    });

    return {
      type: 'tasks-updated',
      batchSize: events.length,
      processedAt,
      tasks,
    };
  }

  private extractShotIdFromTask(task: TaskRecord): string | undefined {
    // Check all possible locations for shot_id
    const metadata = task.metadata as Record<string, unknown> | undefined;
    const params = task.params as Record<string, unknown> | undefined;
    const orchestratorDetails = params?.orchestrator_details as Record<string, unknown> | undefined;
    const originalParams = params?.originalParams as Record<string, unknown> | undefined;
    const originalOrchestrator = originalParams?.orchestrator_details as Record<string, unknown> | undefined;
    const fullOrchestrator = params?.full_orchestrator_payload as Record<string, unknown> | undefined;

    const shotId =
      metadata?.shot_id ||
      metadata?.shotId ||
      params?.shot_id ||
      orchestratorDetails?.shot_id ||
      originalOrchestrator?.shot_id ||
      fullOrchestrator?.shot_id;

    return typeof shotId === 'string' ? shotId : undefined;
  }

  // ===========================================================================
  // Private: Generation Processing
  // ===========================================================================

  private processGenerationInserts(
    events: RawDatabaseEvent[],
    processedAt: number
  ): GenerationsInsertedEvent {
    const generations = events.map((e) => {
      const record = e.new as unknown as GenerationRecord;
      return {
        id: record.id,
        projectId: record.project_id,
        shotId: record.shot_id,
        parentGenerationId: record.parent_generation_id || record.based_on || undefined,
        hasLocation: !!record.location,

      delete nextScopes[scopeKey];
      return { scopes: nextScopes };
    });
  },
  resetAll: () => {
    set({ scopes: {} });
  },
}));

function useRealtimeTaskStore<T>(
  selector: (state: RealtimeStoreState) => T,
  equalityFn?: (left: T, right: T) => boolean,
): T {
  return useStoreWithEqualityFn(realtimeTaskStore, selector, equalityFn);
}

export function useRealtimeTask(taskId: string, projectId?: string | null): Task | null {
  return useRealtimeTaskStore((state) => {
    const scopeKey = resolveScopeKey(projectId);
    if (!scopeKey || !taskId) {
      return null;
    }

    return state.scopes[scopeKey]?.tasks[taskId] ?? null;
  });
}

export function useRealtimePendingGenerationTasks(
  generationId: string | null | undefined,
  projectId?: string | null,
): { pendingCount: number; pendingTasks: readonly PendingGenerationTaskSnapshot[] } {
  return useRealtimeTaskStore((state) => {
    const scopeKey = resolveScopeKey(projectId);
    if (!scopeKey || !generationId) {
      return {
        pendingCount: 0,
        pendingTasks: EMPTY_PENDING_TASK_ARRAY,
      };
    }

    const pendingTasks = state.scopes[scopeKey]?.pendingTasksByGeneration[generationId] ?? EMPTY_PENDING_TASK_ARRAY;
    return {
      pendingCount: pendingTasks.length,
      pendingTasks,
    };
  }, shallow);
}

export function upsertRealtimeTaskSnapshot(task: Task, projectId?: string | null): Task | null {
  return realtimeTaskStore.getState().upsertTask(task, projectId);
}

export function upsertRealtimeTaskSnapshots(tasks: readonly Task[], projectId?: string | null): Task[] {
  return realtimeTaskStore.getState().upsertTasks(tasks, projectId);
}

export function seedRealtimeTaskFromRow(row: unknown, projectId?: string | null): Task | null {
  if (!isTaskDbRow(row)) {
    return null;
  }

  return upsertRealtimeTaskSnapshot(mapTaskDbRowToTask(row), projectId);
}

export function seedRealtimeTasksFromRows(rows: readonly unknown[], projectId?: string | null): Task[] {
  const tasks = rows.flatMap((row) => (isTaskDbRow(row) ? [mapTaskDbRowToTask(row)] : []));
  return upsertRealtimeTaskSnapshots(tasks, projectId);
}

export function resetRealtimeTaskScope(projectId?: string | null): void {
  realtimeTaskStore.getState().resetScope(projectId);
}

export function __resetRealtimeTaskStoreForTests(): void {
  realtimeTaskStore.getState().resetAll();
}

import type { Json } from '@/integrations/supabase/jsonTypes';
import type { Task } from '@/types/tasks';

export interface TaskDbRow {
  id: string;
  task_type: string;
  params: Json | null;
  status: Task['status'];
  dependant_on?: string[] | null;
  output_location?: string | null;
  created_at: string;
  updated_at?: string | null;
  project_id: string;
  cost_cents?: number | null;
  generation_started_at?: string | null;
  generation_processed_at?: string | null;
  error_message?: string | null;
}

function isStringOrNull(value: unknown): value is string | null {
  return value === null || typeof value === 'string';
}

function isStringArrayOrNull(value: unknown): value is string[] | null {
  return value === null || (Array.isArray(value) && value.every((item) => typeof item === 'string'));
}

export function isTaskDbRow(value: unknown): value is TaskDbRow {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return false;
  }

  const row = value as Record<string, unknown>;

  if (
    typeof row.id !== 'string'
    || typeof row.task_type !== 'string'
    || typeof row.status !== 'string'
    || typeof row.created_at !== 'string'
    || typeof row.project_id !== 'string'
  ) {
    return false;
  }

  if (row.updated_at !== undefined && !isStringOrNull(row.updated_at)) return false;
  if (row.output_location !== undefined && !isStringOrNull(row.output_location)) return false;
  if (row.error_message !== undefined && !isStringOrNull(row.error_message)) return false;
  if (row.generation_started_at !== undefined && !isStringOrNull(row.generation_started_at)) return false;
  if (row.generation_processed_at !== undefined && !isStringOrNull(row.generation_processed_at)) return false;
  if (row.cost_cents !== undefined && row.cost_cents !== null && typeof row.cost_cents !== 'number') return false;
  if (row.dependant_on !== undefined && !isStringArrayOrNull(row.dependant_on)) return false;

  return true;
}

function mapTaskParams(params: Json | null): Record<string, unknown> {
  return (params && typeof params === 'object' && !Array.isArray(params))
    ? (params as Record<string, unknown>)
    : {};
}

export function mapTaskDbRowToTask(row: TaskDbRow): Task {
  return {
    id: row.id,
    taskType: row.task_type,
    params: mapTaskParams(row.params),
    status: row.status,
    dependantOn: row.dependant_on ?? undefined,
    outputLocation: row.output_location ?? undefined,
    createdAt: row.created_at,
    updatedAt: row.updated_at ?? undefined,
    projectId: row.project_id,
    costCents: row.cost_cents ?? undefined,
    generationStartedAt: row.generation_started_at ?? undefined,
    generationProcessedAt: row.generation_processed_at ?? undefined,
    errorMessage: row.error_message ?? undefined,
  };
}

import { getSupabaseClient } from '@/integrations/supabase/client';
import type { Task } from '@/types/tasks';
import { isTaskDbRow, mapTaskDbRowToTask } from '@/shared/lib/taskRowMapper';
import {
  createInvalidRowShapeError,
  createRepositoryQueryError,
  isRepositoryNoRowsError,
} from './repositoryErrors';

export async function fetchTaskInProject(taskId: string, projectId: string): Promise<Task | null> {
  const { data, error } = await getSupabaseClient()
    .from('tasks')
    .select('*')
    .eq('id', taskId)
    .eq('project_id', projectId)
    .maybeSingle();

  if (error) {
    if (isRepositoryNoRowsError(error)) {
      return null;
    }
    throw createRepositoryQueryError('task', error, { taskId, projectId });
  }
  if (!data) {
    return null;
  }
  if (!isTaskDbRow(data)) {
    throw createInvalidRowShapeError('task', { taskId, projectId });
  }

  return mapTaskDbRowToTask(data);
}

