import React from 'react';
import { renderHook, RenderHookOptions } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';

/**
 * Create a fresh QueryClient with retries and caching disabled for tests.
 */
function createTestQueryClient(): QueryClient {
  return new QueryClient({
    defaultOptions: {
      queries: {
        retry: false,
        gcTime: 0,
        staleTime: 0,
      },
      mutations: {
        retry: false,
      },
    },
  });
}

// Default mock auth context value
const defaultAuthContext = {
  userId: 'test-user-id',
  isAuthenticated: true,
  isLoading: false,
};

// Default mock project context value
const defaultProjectContext = {
  projects: [],
  selectedProjectId: 'test-project-id',
  setSelectedProjectId: () => {},
  isLoadingProjects: false,
  fetchProjects: async () => {},
  addNewProject: async () => null,
  isCreatingProject: false,
  updateProject: async () => false,
  isUpdatingProject: false,
  deleteProject: async () => false,
  isDeletingProject: false,
  userId: 'test-user-id',
};

interface ProviderOptions {
  authContext?: Partial<typeof defaultAuthContext>;
  projectContext?: Partial<typeof defaultProjectContext>;
  queryClient?: QueryClient;
}

/**
 * Creates a wrapper component that provides QueryClient, Auth, and Project contexts.
 * Auth and Project are provided via simple React contexts to avoid importing the real providers
 * (which have side effects like supabase connections).
 */
function createWrapper(options: ProviderOptions = {}) {
  const queryClient = options.queryClient ?? createTestQueryClient();
  const _authValue = { ...defaultAuthContext, ...options.authContext };
  const _projectValue = { ...defaultProjectContext, ...options.projectContext };

  return function TestProviders({ children }: { children: React.ReactNode }) {
    return (
      <QueryClientProvider client={queryClient}>
        {children}
      </QueryClientProvider>
    );
  };
}

/**
 * Render a hook wrapped with test providers (QueryClient).
 * Use for hook tests that need React Query context.
 */
export function renderHookWithProviders<TResult, TProps>(
  hook: (props: TProps) => TResult,
  options: ProviderOptions & Omit<RenderHookOptions<TProps>, 'wrapper'> = {},
) {
  const { authContext, projectContext, queryClient, ...hookOptions } = options;
  const Wrapper = createWrapper({ authContext, projectContext, queryClient });
  return renderHook(hook, { wrapper: Wrapper, ...hookOptions });
}

import { getProjectSelectionFallbackId } from '@/shared/contexts/projectSelectionStore';

export function resolveTaskProjectScope(projectId?: string | null): string | null {
  if (projectId && projectId.trim().length > 0) {
    return projectId;
  }

  const selectedProjectId = getProjectSelectionFallbackId();
  if (selectedProjectId && selectedProjectId.trim().length > 0) {
    return selectedProjectId;
  }

  return null;
}

/**
 * RealtimeProvider Tests
 *
 * Tests for the realtime connection provider.
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, act } from '@testing-library/react';

// Mock all external dependencies
let statusChangeCallback: ((state: Record<string, unknown>) => void) | null = null;
const mockRealtimeConnection = {
  connect: vi.fn().mockResolvedValue(true),
  disconnect: vi.fn().mockResolvedValue(undefined),
  reset: vi.fn(),
  getState: vi.fn().mockReturnValue({
    status: 'disconnected',
    projectId: null,
    error: null,
    statusChangedAt: Date.now(),
    reconnectAttempt: 0,
    nextRetryAt: null,
  }),
  onStatusChange: vi.fn().mockImplementation((cb: (state: Record<string, unknown>) => void) => {
    statusChangeCallback = cb;
    // Immediately call with current state per the implementation
    cb({
      status: 'disconnected',
      projectId: null,
      error: null,
      statusChangedAt: Date.now(),
      reconnectAttempt: 0,
      nextRetryAt: null,
    });
    return () => {
      statusChangeCallback = null;
    };
  }),
  onEvent: vi.fn().mockImplementation((_cb: (event: Record<string, unknown>) => void) => {
    return () => undefined;
  }),
};

vi.mock('@/shared/contexts/ProjectContext', () => ({
  useProject: vi.fn().mockReturnValue({ selectedProjectId: 'proj-1' }),
}));

vi.mock('@/shared/realtime/RealtimeConnection', () => ({
  getRealtimeConnection: vi.fn(() => mockRealtimeConnection),
}));

vi.mock('@/shared/realtime/RealtimeEventProcessor', () => ({
  realtimeEventProcessor: {
    process: vi.fn(),
    clear: vi.fn(),
  },
}));

vi.mock('@/shared/realtime/DataFreshnessManager', () => ({
  dataFreshnessManager: {
    reset: vi.fn(),
  },
}));

vi.mock('@/shared/hooks/useRealtimeInvalidation', () => ({
  useRealtimeInvalidation: vi.fn(),
}));

import { RealtimeProvider, useRealtime } from '../RealtimeProvider';

// Test consumer component
function RealtimeConsumer() {
  const ctx = useRealtime();
  return (
    <div>
      <span data-testid="status">{ctx.status}</span>
      <span data-testid="isConnected">{String(ctx.isConnected)}</span>
      <span data-testid="isConnecting">{String(ctx.isConnecting)}</span>
      <span data-testid="isFailed">{String(ctx.isFailed)}</span>
      <span data-testid="error">{ctx.error ?? 'null'}</span>
      <button data-testid="reconnect" onClick={ctx.reconnect}>
        Reconnect
      </button>
    </div>
  );
}

describe('RealtimeProvider', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    statusChangeCallback = null;
  });

  it('renders children', () => {
    render(
      <RealtimeProvider>
        <div data-testid="child">Hello</div>
      </RealtimeProvider>
    );

    expect(screen.getByTestId('child')).toHaveTextContent('Hello');
  });

  it('provides initial disconnected state', () => {
    render(
      <RealtimeProvider>
        <RealtimeConsumer />
      </RealtimeProvider>
    );

    expect(screen.getByTestId('status')).toHaveTextContent('disconnected');
    expect(screen.getByTestId('isConnected')).toHaveTextContent('false');
    expect(screen.getByTestId('isConnecting')).toHaveTextContent('false');
    expect(screen.getByTestId('isFailed')).toHaveTextContent('false');
    expect(screen.getByTestId('error')).toHaveTextContent('null');
  });

  it('connects when project is selected', () => {
    render(
      <RealtimeProvider>
        <RealtimeConsumer />
      </RealtimeProvider>
    );

    expect(mockRealtimeConnection.connect).toHaveBeenCalledWith('proj-1');
  });

  it('subscribes to status changes', () => {
    render(
      <RealtimeProvider>
        <RealtimeConsumer />
      </RealtimeProvider>
    );

    expect(mockRealtimeConnection.onStatusChange).toHaveBeenCalled();
  });

  it('wires connection events to event processor', () => {
    render(
      <RealtimeProvider>
        <RealtimeConsumer />
      </RealtimeProvider>
    );

    expect(mockRealtimeConnection.onEvent).toHaveBeenCalled();
  });

  it('updates state when status changes', () => {
    render(
      <RealtimeProvider>
        <RealtimeConsumer />
      </RealtimeProvider>
    );

    // Simulate status change to connected
    act(() => {
      if (statusChangeCallback) {
        statusChangeCallback({
          status: 'connected',
          projectId: 'proj-1',
          error: null,
          statusChangedAt: Date.now(),
          reconnectAttempt: 0,
          nextRetryAt: null,
        });
      }
    });

    expect(screen.getByTestId('status')).toHaveTextContent('connected');
    expect(screen.getByTestId('isConnected')).toHaveTextContent('true');
  });

  it('provides reconnect function', () => {
    render(
      <RealtimeProvider>
        <RealtimeConsumer />
      </RealtimeProvider>
    );

    act(() => {
      screen.getByTestId('reconnect').click();
    });

    expect(mockRealtimeConnection.reset).toHaveBeenCalled();
    expect(mockRealtimeConnection.connect).toHaveBeenCalledWith('proj-1');
  });

  describe('useRealtime hook', () => {
    it('returns default values when used outside provider', () => {
      // useRealtime uses a context with default value, so it should not throw
      function OutsideConsumer() {
        const ctx = useRealtime();
        return <span data-testid="status">{ctx.status}</span>;
      }

      render(<OutsideConsumer />);
      expect(screen.getByTestId('status')).toHaveTextContent('disconnected');
    });
  });
});

