import { useQuery } from '@tanstack/react-query';
import { getSupabaseClient } from '@/integrations/supabase/client';
import { getVisibleTaskTypes } from '@/shared/lib/tasks/taskConfig';
import { useSmartPollingConfig } from '@/shared/hooks/useSmartPolling';
import { QUERY_PRESETS, STANDARD_RETRY, STANDARD_RETRY_DELAY } from '@/shared/lib/query/queryDefaults';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';
import { dataFreshnessManager } from '@/shared/realtime/DataFreshnessManager';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import {
  TASK_FAILURE_STATUSES,
  TASK_PROCESSING_STATUSES,
} from '@/shared/lib/tasks/taskStatusSemantics';
import { applyRootTaskFilter } from '@/shared/lib/tasks/orchestratorReference';
import {
  operationFailure,
  operationSuccess,
  type OperationResult,
} from '@/shared/lib/operationResult';

type TaskStatusCountsQuery = 'processing' | 'success' | 'failure';

interface TaskStatusCountsResult {
  processing: number;
  recentSuccesses: number;
  recentFailures: number;
  degraded: boolean;
  failedQueries: TaskStatusCountsQuery[];
  errorCode?: 'task_status_counts_partial_failure';
  operation: OperationResult<{
    processing: number;
    recentSuccesses: number;
    recentFailures: number;
  }>;
}

function buildEmptyTaskStatusCountsResult(): TaskStatusCountsResult {
  const zeroCounts = {
    processing: 0,
    recentSuccesses: 0,
    recentFailures: 0,
  };

  return {
    ...zeroCounts,
    degraded: false,
    failedQueries: [],
    operation: operationSuccess(zeroCounts, { policy: 'best_effort' }),
  };
}

function resolveSettledCountResult(
  projectId: string,
  result: PromiseSettledResult<{ count: number | null; error: unknown }>,
  queryType: TaskStatusCountsQuery,
): { count: number; failed: boolean } {
  if (result.status === 'fulfilled') {
    const { count, error } = result.value;
    if (error) {
      normalizeAndPresentError(error, {
        context: `useTaskStatusCounts.${queryType}`,
        showToast: false,
        logData: { projectId },
      });
      return { count: 0, failed: true };
    }
    return { count: count || 0, failed: false };
  }

  normalizeAndPresentError(
    result.reason instanceof Error ? result.reason : new Error(String(result.reason)),
    {
      context: `useTaskStatusCounts.${queryType}`,
      showToast: false,
      logData: { projectId },
    },
  );
  return { count: 0, failed: true };
}

function buildTaskStatusCountsResult(
  projectId: string,
  counts: { processing: number; success: number; failure: number },
  failedQueries: TaskStatusCountsQuery[],
): TaskStatusCountsResult {
  return {
    processing: counts.processing,
    recentSuccesses: counts.success,
    recentFailures: counts.failure,
    degraded: failedQueries.length > 0,
    failedQueries,
    ...(failedQueries.length > 0
      ? { errorCode: 'task_status_counts_partial_failure' as const }
      : {}),
    operation:
      failedQueries.length > 0
        ? operationFailure(new Error('Task status counts query partially failed'), {
            errorCode: 'task_status_counts_partial_failure',
            policy: 'degrade',
            recoverable: true,
            message: `Partial task status count failure (${failedQueries.join(', ')})`,
            cause: { failedQueries, projectId },
          })
        : operationSuccess(
            {
              processing: counts.processing,
              recentSuccesses: counts.success,
              recentFailures: counts.failure,
            },
            { policy: 'best_effort' },
          ),
  };
}

function trackTaskStatusCountsFreshness(
  projectId: string,
  failedQueries: TaskStatusCountsQuery[],
  settledResults: [
    PromiseSettledResult<{ count: number | null; error: unknown }>,
    PromiseSettledResult<{ count: number | null; error: unknown }>,
    PromiseSettledResult<{ count: number | null; error: unknown }>,
  ],
): void {
  if (failedQueries.length === 0) {
    dataFreshnessManager.onFetchSuccess(taskQueryKeys.statusCounts(projectId));
    return;
  }

  const [processingResult, successResult, failureResult] = settledResults;
  const errorReason =
    processingResult.status === 'rejected'
      ? processingResult.reason
      : successResult.status === 'rejected'
        ? successResult.reason
        : failureResult.status === 'rejected'
          ? failureResult.reason
          : new Error('Query returned error');

  dataFreshnessManager.onFetchFailure(
    taskQueryKeys.statusCounts(projectId),
    errorReason as Error,
  );
}

interface FetchTaskStatusCountsOptions {
  projectId: string | null;
  allProjectIds?: string[];
}

function applyProjectScope(
  query: ReturnType<ReturnType<typeof getSupabaseClient>['from']>['select'],
  projectId: string | null,
  allProjectIds?: string[],
) {
  if (allProjectIds && allProjectIds.length > 0) {
    return query.in('project_id', allProjectIds);
  }
  if (projectId) {
    return query.eq('project_id', projectId);
  }
  return query;
}

async function fetchTaskStatusCounts(options: FetchTaskStatusCountsOptions): Promise<TaskStatusCountsResult> {
  const { projectId, allProjectIds } = options;
  const isAllProjects = allProjectIds && allProjectIds.length > 0;

  if (!projectId && !isAllProjects) {
    return buildEmptyTaskStatusCountsResult();
  }

  // Use projectId for freshness tracking; fall back to synthetic key for all-projects mode
  const trackingId = projectId ?? '__all-projects__';

  const visibleTaskTypes = getVisibleTaskTypes();
  const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();
  const supabase = getSupabaseClient();

  const settledResults = await Promise.allSettled([
    applyRootTaskFilter(
      applyProjectScope(
        supabase
          .from('tasks')
          .select('id', { count: 'exact', head: true }),
        projectId,
        allProjectIds,
      )
        .in('status', [...TASK_PROCESSING_STATUSES])
        .in('task_type', visibleTaskTypes),
    ),
    applyRootTaskFilter(
      applyProjectScope(
        supabase
          .from('tasks')
          .select('id', { count: 'exact', head: true }),
        projectId,
        allProjectIds,
      )
        .eq('status', 'Complete')
        .gte('generation_processed_at', oneHourAgo)
        .in('task_type', visibleTaskTypes),
    ),
    applyRootTaskFilter(
      applyProjectScope(
        supabase
          .from('tasks')
          .select('id', { count: 'exact', head: true }),
        projectId,
        allProjectIds,
      )
        .in('status', [...TASK_FAILURE_STATUSES])
        .gte('updated_at', oneHourAgo)
        .in('task_type', visibleTaskTypes),
    ),
  ]) as [
    PromiseSettledResult<{ count: number | null; error: unknown }>,
    PromiseSettledResult<{ count: number | null; error: unknown }>,
    PromiseSettledResult<{ count: number | null; error: unknown }>,
  ];

  const failedQueries: TaskStatusCountsQuery[] = [];
  const processing = resolveSettledCountResult(trackingId, settledResults[0], 'processing');
  if (processing.failed) failedQueries.push('processing');

  const success = resolveSettledCountResult(trackingId, settledResults[1], 'success');
  if (success.failed) failedQueries.push('success');

  const failure = resolveSettledCountResult(trackingId, settledResults[2], 'failure');
  if (failure.failed) failedQueries.push('failure');

  trackTaskStatusCountsFreshness(trackingId, failedQueries, settledResults);

  return buildTaskStatusCountsResult(
    trackingId,
    {
      processing: processing.count,
      success: success.count,
      failure: failure.count,
    },
    failedQueries,
  );
}

// Hook to get status counts for indicators
export const useTaskStatusCounts = (
  projectId: string | null,
  options?: { allProjectIds?: string[] },
) => {
  const allProjectIds = options?.allProjectIds;
  const isAllProjects = !!allProjectIds?.length;
  const cacheProjectId = isAllProjects ? '__all-projects__' : (projectId ?? '__no-project__');
  const smartPollingConfig = useSmartPollingConfig(taskQueryKeys.statusCounts(cacheProjectId));

  return useQuery({
    queryKey: taskQueryKeys.statusCounts(cacheProjectId),
    queryFn: () => fetchTaskStatusCounts({ projectId, allProjectIds }),
    enabled: isAllProjects || !!projectId,
    ...smartPollingConfig,
    refetchIntervalInBackground: true,
    retry: STANDARD_RETRY,
    retryDelay: STANDARD_RETRY_DELAY,

/**
 * usePendingGenerationTasks Hook
 *
 * Tracks tasks that are "Queued" or "In Progress" that will create
 * variants or derived generations from a given source generation.
 *
 * Works for both images and videos - checks task params for source generation references.
 */

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { TASK_STATUS } from '@/types/tasks';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';

interface PendingGenerationTask {
  id: string;
  status: string;
  task_type: string;
}

interface UsePendingGenerationTasksReturn {
  /** Number of pending tasks that will create variants/derived from this generation */
  pendingCount: number;
  /** The pending tasks */
  pendingTasks: PendingGenerationTask[];
  /** Loading state */
  isLoading: boolean;
}

/**
 * Check if task params reference a specific generation ID as a source.
 * Checks common param fields where source generation is stored.
 */
export function taskReferencesGeneration(
  params: Record<string, unknown> | null,
  generationId: string
): boolean {
  if (!params || !generationId) return false;

  // Direct source references
  if (params.based_on === generationId) return true;
  if (params.source_generation_id === generationId) return true;
  if (params.generation_id === generationId) return true;
  if (params.input_generation_id === generationId) return true;
  if (params.parent_generation_id === generationId) return true;
  if (params.start_image_generation_id === generationId) return true;
  if (params.end_image_generation_id === generationId) return true;
  // Video segment tasks use pair_shot_generation_id
  if (params.pair_shot_generation_id === generationId) return true;
  if (Array.isArray(params.input_image_generation_ids) && params.input_image_generation_ids.includes(generationId)) {
    return true;
  }

  // Check nested in orchestrator_details
  const orchDetails = params.orchestrator_details as Record<string, unknown> | undefined;
  if (orchDetails) {
    if (orchDetails.based_on === generationId) return true;
    if (orchDetails.source_generation_id === generationId) return true;
    if (orchDetails.parent_generation_id === generationId) return true;
    if (
      Array.isArray(orchDetails.input_image_generation_ids)
      && orchDetails.input_image_generation_ids.includes(generationId)
    ) {
      return true;
    }
    // Check pair_shot_generation_ids array
    if (Array.isArray(orchDetails.pair_shot_generation_ids)) {
      if (orchDetails.pair_shot_generation_ids.includes(generationId)) return true;
    }
  }

  // Check full_orchestrator_payload
  const fullPayload = params.full_orchestrator_payload as Record<string, unknown> | undefined;
  if (fullPayload) {
    if (fullPayload.based_on === generationId) return true;
    if (fullPayload.source_generation_id === generationId) return true;
    if (fullPayload.parent_generation_id === generationId) return true;
  }

  // Check individual_segment_params (used by individual_travel_segment)
  const individualParams = params.individual_segment_params as Record<string, unknown> | undefined;
  if (individualParams) {
    if (individualParams.pair_shot_generation_id === generationId) return true;
  }

  return false;
}

export function usePendingGenerationTasks(
  generationId: string | null | undefined,
  projectId: string | null | undefined
): UsePendingGenerationTasksReturn {
  // Query pending tasks for this project
  const { data: pendingTasks, isLoading } = useQuery({
    queryKey: [...taskQueryKeys.pendingGeneration(generationId!), projectId],
    queryFn: async () => {
      if (!generationId || !projectId) return [];

      // Query tasks that are Queued or In Progress
      const { getSupabaseClient } = await import('@/integrations/supabase/client');
      const { data, error } = await getSupabaseClient().from('tasks')
        .select('id, status, task_type, params')
        .eq('project_id', projectId)
        .in('status', [TASK_STATUS.QUEUED, TASK_STATUS.IN_PROGRESS]);

      if (error) {
        console.error('[usePendingGenerationTasks] Query error:', error);
        return [];
      }

      // Filter to tasks that reference this generation
      const matchingTasks: PendingGenerationTask[] = (data || [])
        .filter(task => taskReferencesGeneration(task.params as Record<string, unknown> | null, generationId))
        .map(task => ({
          id: task.id,
          status: task.status,
          task_type: task.task_type,
        }));

      return matchingTasks;
    },
    enabled: !!generationId && !!projectId,
    // Poll to catch status changes
    refetchInterval: 5000,
    // Mark as stale immediately so invalidations trigger refetch
    staleTime: 0,
    // Short cache time - don't keep stale data around
    gcTime: 10000,
    // Always refetch when window regains focus
    refetchOnWindowFocus: 'always',
  });

  const result = useMemo(() => ({
    pendingCount: pendingTasks?.length || 0,
    pendingTasks: pendingTasks || [],
    isLoading,
  }), [pendingTasks, isLoading]);

  return result;
}

