import { shallow } from 'zustand/shallow';
import { useStoreWithEqualityFn } from 'zustand/traditional';
import { createStore } from 'zustand/vanilla';
import { mapTaskDbRowToTask, isTaskDbRow } from '@/shared/lib/taskRowMapper';
import { resolveTaskProjectScope } from '@/shared/lib/tasks/resolveTaskProjectScope';
import { deepEqual } from '@/shared/lib/utils/deepEqual';
import { TASK_STATUS, type Task } from '@/types/tasks';

export interface PendingGenerationTaskSnapshot {
  id: string;
  status: Task['status'];
  task_type: Task['taskType'];
}

interface RealtimeTaskScopeState {
  tasks: Record<string, Task>;
  taskGenerationIds: Record<string, readonly string[]>;
  pendingTaskIdsByGeneration: Record<string, readonly string[]>;
  pendingTasksByGeneration: Record<string, readonly PendingGenerationTaskSnapshot[]>;
}

interface RealtimeStoreState {
  scopes: Record<string, RealtimeTaskScopeState>;
  upsertTask: (task: Task, projectId?: string | null) => Task | null;
  upsertTasks: (tasks: readonly Task[], projectId?: string | null) => Task[];
  resetScope: (projectId?: string | null) => void;
  resetAll: () => void;
}

const EMPTY_TASKS = Object.freeze({}) as Record<string, Task>;
const EMPTY_GENERATION_IDS = Object.freeze({}) as Record<string, readonly string[]>;
const EMPTY_PENDING_IDS = Object.freeze({}) as Record<string, readonly string[]>;
const EMPTY_PENDING_TASKS = Object.freeze({}) as Record<string, readonly PendingGenerationTaskSnapshot[]>;
const EMPTY_STRING_ARRAY = Object.freeze([]) as readonly string[];
const EMPTY_PENDING_TASK_ARRAY = Object.freeze([]) as readonly PendingGenerationTaskSnapshot[];

function createEmptyScopeState(): RealtimeTaskScopeState {
  return {
    tasks: EMPTY_TASKS,
    taskGenerationIds: EMPTY_GENERATION_IDS,
    pendingTaskIdsByGeneration: EMPTY_PENDING_IDS,
    pendingTasksByGeneration: EMPTY_PENDING_TASKS,
  };
}

function isPendingTaskStatus(status: Task['status']): boolean {
  return status === TASK_STATUS.QUEUED || status === TASK_STATUS.IN_PROGRESS;
}

function addGenerationId(target: Set<string>, value: unknown): void {
  if (typeof value !== 'string') {
    return;
  }

  const trimmed = value.trim();
  if (trimmed) {
    target.add(trimmed);
  }
}

function addGenerationIdsFromArray(target: Set<string>, value: unknown): void {
  if (!Array.isArray(value)) {
    return;
  }

  value.forEach((item) => addGenerationId(target, item));
}

function addGenerationIdsFromRecord(target: Set<string>, value: unknown): void {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return;
  }

  const record = value as Record<string, unknown>;
  addGenerationId(target, record.based_on);
  addGenerationId(target, record.source_generation_id);
  addGenerationId(target, record.generation_id);
  addGenerationId(target, record.input_generation_id);
  addGenerationId(target, record.parent_generation_id);
  addGenerationId(target, record.start_image_generation_id);
  addGenerationId(target, record.end_image_generation_id);
  addGenerationId(target, record.pair_shot_generation_id);
  addGenerationIdsFromArray(target, record.input_image_generation_ids);
  addGenerationIdsFromArray(target, record.pair_shot_generation_ids);
}

export function collectTaskGenerationIds(task: Task): readonly string[] {
  if (!isPendingTaskStatus(task.status)) {
    return EMPTY_STRING_ARRAY;
  }

  const generationIds = new Set<string>();
  addGenerationIdsFromRecord(generationIds, task.params);

  const params = task.params as Record<string, unknown>;
  addGenerationIdsFromRecord(generationIds, params.orchestrator_details);
  addGenerationIdsFromRecord(generationIds, params.full_orchestrator_payload);
  addGenerationIdsFromRecord(generationIds, params.individual_segment_params);

  if (generationIds.size === 0) {
    return EMPTY_STRING_ARRAY;
  }

  return Object.freeze(Array.from(generationIds));
}

function areStringArraysEqual(left: readonly string[], right: readonly string[]): boolean {
  if (left === right) {
    return true;
  }

  if (left.length !== right.length) {
    return false;
  }

  for (let index = 0; index < left.length; index += 1) {
    if (left[index] !== right[index]) {
      return false;
    }
  }

  return true;
}

function buildPendingTaskSummaries(
  taskIds: readonly string[],
  tasks: Record<string, Task>,
  previous: readonly PendingGenerationTaskSnapshot[],
): readonly PendingGenerationTaskSnapshot[] {
  if (taskIds.length === 0) {
    return EMPTY_PENDING_TASK_ARRAY;
  }

  const previousById = new Map(previous.map((task) => [task.id, task]));
  const next = taskIds.flatMap((taskId) => {
    const task = tasks[taskId];
    if (!task || !isPendingTaskStatus(task.status)) {
      return [];
    }

    const existing = previousById.get(task.id);
    if (existing && existing.status === task.status && existing.task_type === task.taskType) {
      return [existing];
    }

    return [{
      id: task.id,
      status: task.status,
      task_type: task.taskType,
    }];
  });

  if (next.length === 0) {
    return EMPTY_PENDING_TASK_ARRAY;
  }

  if (next.length === previous.length && next.every((task, index) => task === previous[index])) {
    return previous;
  }

  return Object.freeze(next);
}

function resolveScopeKey(projectId?: string | null): string | null {
  return resolveTaskProjectScope(projectId);
}

function resolveTaskScopeKey(task: Task, projectId?: string | null): string | null {
  return resolveTaskProjectScope(projectId ?? task.projectId);
}

function getScopeState(
  scopes: Record<string, RealtimeTaskScopeState>,
  scopeKey: string,
): RealtimeTaskScopeState {
  return scopes[scopeKey] ?? createEmptyScopeState();
}

function buildUpdatedScopeState(scopeState: RealtimeTaskScopeState, task: Task): RealtimeTaskScopeState {
  const previousTask = scopeState.tasks[task.id];
  const nextTask = previousTask && deepEqual(previousTask, task) ? previousTask : task;
  const previousGenerationIds = scopeState.taskGenerationIds[task.id] ?? EMPTY_STRING_ARRAY;
  const nextGenerationIds = collectTaskGenerationIds(nextTask);
  const taskChanged = previousTask !== nextTask;
  const generationIdsChanged = !areStringArraysEqual(previousGenerationIds, nextGenerationIds);

  if (!taskChanged && !generationIdsChanged) {
    return scopeState;
  }

  const nextTasks = taskChanged
    ? { ...scopeState.tasks, [task.id]: nextTask }
    : scopeState.tasks;

  const nextTaskGenerationIds = { ...scopeState.taskGenerationIds };
  if (nextGenerationIds.length > 0) {
    nextTaskGenerationIds[task.id] = nextGenerationIds;
  } else {
    delete nextTaskGenerationIds[task.id];
  }

  const nextPendingTaskIdsByGeneration = { ...scopeState.pendingTaskIdsByGeneration };
  const nextPendingTasksByGeneration = { ...scopeState.pendingTasksByGeneration };

  const affectedGenerationIds = new Set<string>([
    ...previousGenerationIds,
    ...nextGenerationIds,
  ]);

  affectedGenerationIds.forEach((generationId) => {
    const previousTaskIds = scopeState.pendingTaskIdsByGeneration[generationId] ?? EMPTY_STRING_ARRAY;
    const shouldInclude = nextGenerationIds.includes(generationId);
    const alreadyIncluded = previousTaskIds.includes(task.id);

    let nextTaskIds = previousTaskIds;
    if (shouldInclude && !alreadyIncluded) {
      nextTaskIds = Object.freeze([...previousTaskIds, task.id]);
    } else if (!shouldInclude && alreadyIncluded) {
      nextTaskIds = Object.freeze(previousTaskIds.filter((pendingTaskId) => pendingTaskId !== task.id));
    }

    if (nextTaskIds.length === 0) {
      delete nextPendingTaskIdsByGeneration[generationId];
    } else {
      nextPendingTaskIdsByGeneration[generationId] = nextTaskIds;
    }

    const previousPendingTasks = scopeState.pendingTasksByGeneration[generationId] ?? EMPTY_PENDING_TASK_ARRAY;
    const nextPendingTasks = buildPendingTaskSummaries(nextTaskIds, nextTasks, previousPendingTasks);

    if (nextPendingTasks.length === 0) {
      delete nextPendingTasksByGeneration[generationId];
    } else {
      nextPendingTasksByGeneration[generationId] = nextPendingTasks;
    }
  });

  return {
    tasks: nextTasks,
    taskGenerationIds: nextTaskGenerationIds,
    pendingTaskIdsByGeneration: nextPendingTaskIdsByGeneration,
    pendingTasksByGeneration: nextPendingTasksByGeneration,
  };
}

function upsertTaskIntoScopes(
  scopes: Record<string, RealtimeTaskScopeState>,
  task: Task,
  projectId?: string | null,
): Record<string, RealtimeTaskScopeState> {
  const scopeKey = resolveTaskScopeKey(task, projectId);
  if (!scopeKey) {
    return scopes;
  }

  const scopeState = getScopeState(scopes, scopeKey);
  const nextScopeState = buildUpdatedScopeState(scopeState, task);
  if (nextScopeState === scopeState) {
    return scopes;
  }

  return {
    ...scopes,
    [scopeKey]: nextScopeState,
  };
}

const realtimeTaskStore = createStore<RealtimeStoreState>((set, get) => ({
  scopes: {},
  upsertTask: (task, projectId) => {
    const scopeKey = resolveTaskScopeKey(task, projectId);
    if (!scopeKey) {
      return null;
    }

    set((state) => ({
      scopes: upsertTaskIntoScopes(state.scopes, task, projectId),
    }));

    return get().scopes[scopeKey]?.tasks[task.id] ?? null;
  },
  upsertTasks: (tasks, projectId) => {
    if (tasks.length === 0) {
      return [];
    }

    set((state) => {
      let nextScopes = state.scopes;
      tasks.forEach((task) => {
        nextScopes = upsertTaskIntoScopes(nextScopes, task, projectId);
      });

      return nextScopes === state.scopes
        ? state
        : { scopes: nextScopes };
    });

    return tasks.flatMap((task) => {
      const scopeKey = resolveTaskScopeKey(task, projectId);
      if (!scopeKey) {
        return [];
      }

      const seededTask = get().scopes[scopeKey]?.tasks[task.id];
      return seededTask ? [seededTask] : [];
    });
  },
  resetScope: (projectId) => {
    const scopeKey = resolveScopeKey(projectId);
    if (!scopeKey) {
      return;
    }

    set((state) => {
      if (!(scopeKey in state.scopes)) {
        return state;
      }

      const nextScopes = { ...state.scopes };
      delete nextScopes[scopeKey];

import { useEffect } from 'react';
import { keepPreviousData, useQuery, useQueryClient, type QueryClient, type UseQueryOptions } from '@tanstack/react-query';
import { Task, TaskStatus } from '@/types/tasks';
import { getSupabaseClientResult } from '@/integrations/supabase/client';
import { getVisibleTaskTypes } from '@/shared/lib/tasks/taskConfig';
import { normalizeAndPresentAndRethrow } from '@/shared/lib/errorHandling/runtimeError';
// Removed invalidationRouter - DataFreshnessManager handles all invalidation logic
import { useSmartPollingConfig } from '@/shared/hooks/useSmartPolling';
import { QUERY_PRESETS, STANDARD_RETRY, STANDARD_RETRY_DELAY } from '@/shared/lib/query/queryDefaults';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';
import { useProcessingRefetchGuard } from '@/shared/hooks/tasks/useProcessingRefetchGuard';
import {
  notifyPaginatedTaskFetchFailure,
  notifyPaginatedTaskFetchSuccess,
} from '@/shared/realtime/dataFreshness/taskFetchFreshness';
import {
  fetchPaginatedTasks,
  mapDbTaskToTask,
  type PaginatedTaskQuery,
  type PaginatedTasksResponse as RepositoryPaginatedTasksResponse,
} from '@/shared/hooks/tasks/paginatedTaskRepository';
import { resolveTaskProjectScope } from '@/shared/lib/tasks/resolveTaskProjectScope';
import {
  getRealtimeTaskSnapshot,
  useRealtimeTask,
  upsertRealtimeTaskSnapshot,
} from '@/shared/state/realtimeStore';

// Types for API responses and request bodies
// Ensure these align with your server-side definitions and Task type in @/types/tasks.ts

interface PaginatedTasksParams {
  projectId?: string | null;
  status?: TaskStatus[];
  limit?: number;
  offset?: number;
  taskType?: string | null; // Filter by specific task type
  allProjects?: boolean; // If true, query across all projects
  allProjectIds?: string[]; // List of project IDs to query when allProjects is true
}

export type PaginatedTasksResponse = RepositoryPaginatedTasksResponse;
function createPaginatedTasksQueryFn(filters: PaginatedTaskQuery, cacheProjectKey: string) {
  return async (): Promise<PaginatedTasksResponse> => {
    try {
      const result = await fetchPaginatedTasks(filters);
      notifyPaginatedTaskFetchSuccess(cacheProjectKey);
      return result;
    } catch (error) {
      notifyPaginatedTaskFetchFailure(cacheProjectKey, error);
      normalizeAndPresentAndRethrow(error, {
        context: 'useTasks.fetchPaginatedTasks',
        showToast: false,
        logData: { cacheProjectKey },
      });
    }
  };
}

// Helper to convert DB row (snake_case) to Task interface (camelCase)
// Exported for use in prefetch utilities
export { mapDbTaskToTask };

function seedTaskSnapshot(task: Task | null | undefined, projectId?: string | null): Task | null | undefined {
  if (!task) {
    return task;
  }

  return upsertRealtimeTaskSnapshot(task, projectId) ?? task;
}

async function fetchSingleTask(taskId: string, projectId?: string | null): Promise<Task | null> {
  const effectiveProjectId = resolveTaskProjectScope(projectId);
  const supabaseResult = getSupabaseClientResult();
  if (!supabaseResult.ok) {
    normalizeAndPresentAndRethrow(supabaseResult.error, {
      context: 'useTasks.useGetTask',
      showToast: false,
      logData: { taskId, projectId: effectiveProjectId },
    });
  }

  const { data, error } = await supabaseResult.client
    .from('tasks')
    .select('*')
    .eq('id', taskId)
    .eq('project_id', effectiveProjectId!)
    .maybeSingle();

  if (error) {
    normalizeAndPresentAndRethrow(error, {
      context: 'useTasks.useGetTask',
      showToast: false,
      logData: { taskId, projectId: effectiveProjectId },
    });
  }

  if (!data) {
    return null;
  }

  return seedTaskSnapshot(mapDbTaskToTask(data), effectiveProjectId) ?? null;
}

export function getCachedTaskSnapshot(
  queryClient: QueryClient,
  taskId: string,
  projectId?: string | null,
): Task | null | undefined {
  const effectiveProjectId = resolveTaskProjectScope(projectId);
  if (!taskId || !effectiveProjectId) {
    return undefined;
  }

  const storeTask = getRealtimeTaskSnapshot(taskId, effectiveProjectId);
  if (storeTask) {
    return storeTask;
  }

  const cachedTask = queryClient.getQueryData<Task | null>(
    taskQueryKeys.single(taskId, effectiveProjectId),
  );
  return seedTaskSnapshot(cachedTask, effectiveProjectId);
}

export function createSingleTaskQueryOptions(
  taskId: string,
  projectId?: string | null,
): UseQueryOptions<Task | null, Error> {
  const effectiveProjectId = resolveTaskProjectScope(projectId);

  return {
    queryKey: taskQueryKeys.single(taskId, effectiveProjectId),
    queryFn: () => fetchSingleTask(taskId, effectiveProjectId),
    enabled: !!taskId && !!effectiveProjectId,
    ...QUERY_PRESETS.immutable,
  };
}

export async function fetchAndSeedTaskQuery(
  queryClient: QueryClient,
  taskId: string,
  projectId?: string | null,
): Promise<Task | null> {
  return queryClient.fetchQuery(createSingleTaskQueryOptions(taskId, projectId));
}

// Hook to get a single task by ID
// Uses IMMUTABLE_PRESET since task data rarely changes after creation
export const useGetTask = (taskId: string, projectId?: string | null) => {
  const effectiveProjectId = resolveTaskProjectScope(projectId);
  const queryClient = useQueryClient();
  const storeTask = useRealtimeTask(taskId, effectiveProjectId);

  useEffect(() => {
    getCachedTaskSnapshot(queryClient, taskId, effectiveProjectId);
  }, [effectiveProjectId, queryClient, taskId]);

  const query = useQuery<Task | null, Error>(createSingleTaskQueryOptions(taskId, effectiveProjectId));

  useEffect(() => {
    if (query.data !== undefined) {
      seedTaskSnapshot(query.data, effectiveProjectId);
    }
  }, [effectiveProjectId, query.data]);

  return {
    ...query,
    data: storeTask ?? query.data,
  };
};

// Hook to list tasks with pagination - GALLERY PATTERN
export const usePaginatedTasks = (params: PaginatedTasksParams) => {
  const { projectId, status, limit = 50, offset = 0, taskType, allProjects, allProjectIds } = params;
  const page = Math.floor(offset / limit) + 1;
  const effectiveProjectId: string | null = projectId ?? null;
  const cacheProjectKey = allProjects ? 'all' : effectiveProjectId;
  const safeCacheProjectKey = cacheProjectKey ?? '__no-project__';
  const visibleTaskTypes = getVisibleTaskTypes();
  const smartPollingConfig = useSmartPollingConfig(taskQueryKeys.paginated(safeCacheProjectKey));

  const query = useQuery<PaginatedTasksResponse, Error>({
    queryKey: [...taskQueryKeys.paginated(safeCacheProjectKey), page, limit, status, taskType],
    queryFn: createPaginatedTasksQueryFn({
      allProjects,
      allProjectIds,
      effectiveProjectId,
      status,
      taskType,
      visibleTaskTypes,
      limit,
      offset,
      page,
    }, safeCacheProjectKey),
    enabled: allProjects ? !!allProjectIds?.length : !!effectiveProjectId,
    placeholderData: keepPreviousData,
    ...QUERY_PRESETS.realtimeBacked,
    ...smartPollingConfig,
    refetchIntervalInBackground: true,
    retry: STANDARD_RETRY,
    retryDelay: STANDARD_RETRY_DELAY,
  });

  useProcessingRefetchGuard(status, query);

  return query;
};

/**
 * Utilities for prefetching generation-linked task data.
 *
 * The canonical generation -> task mapping query lives in the generation
 * domain; this module only handles best-effort prefetch.
 */

import { useCallback } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';
import { isUuid } from '@/shared/lib/uuid';
import type { GenerationTaskMappingCacheEntry } from '@/shared/lib/tasks/generationTaskRepository';
import { resolveTaskProjectScope } from '@/shared/lib/tasks/resolveTaskProjectScope';
import { prefetchGenerationTaskMapping } from '@/domains/generation/hooks/tasks/useGenerationTaskMapping';
import { fetchAndSeedTaskQuery, getCachedTaskSnapshot } from './useTasks';

/**
 * Hook to prefetch task data for a generation on hover.
 * Returns a function that can be called onMouseEnter to prefetch
 * both the task ID mapping and the full task data.
 */
export function usePrefetchTaskData() {
  const queryClient = useQueryClient();

  const prefetch = useCallback(async (generationId: string, projectId?: string | null) => {
    const effectiveProjectId = resolveTaskProjectScope(projectId);
    if (!generationId || !effectiveProjectId || !isUuid(generationId)) return;

    // Check if task ID mapping is already cached (including { taskId: null } for no-task generations)
    let taskId: string | null = null;
    const cachedMapping = queryClient.getQueryData(taskQueryKeys.generationMapping(generationId)) as GenerationTaskMappingCacheEntry | undefined;

    if (cachedMapping !== undefined) {
      // Already cached - use the cached value (could be null if no task)
      taskId = cachedMapping.taskId;
    } else {
      // Not cached - fetch the task ID mapping
      try {
        const result = await prefetchGenerationTaskMapping(queryClient, generationId);
        taskId = result?.taskId ?? null;
      } catch {
        return;
      }
    }

    // Prefetch the full task data if we have a task ID and it's not cached
    if (taskId) {
      const cachedTask = getCachedTaskSnapshot(queryClient, taskId, effectiveProjectId);
      if (!cachedTask) {
        try {
          await fetchAndSeedTaskQuery(queryClient, taskId, effectiveProjectId);
        } catch {
          // Silently fail - prefetch is best-effort
        }
      }
    }
  }, [queryClient]);

  return prefetch;
}

/**
 * Hook to prefetch a task directly by task ID.
 * Use this when you already have the task ID (e.g., from variant.params.source_task_id).
 */
export function usePrefetchTaskById() {
  const queryClient = useQueryClient();

  const prefetch = useCallback(async (taskId: string, projectId?: string | null) => {
    const effectiveProjectId = resolveTaskProjectScope(projectId);
    if (!taskId || !effectiveProjectId || !isUuid(taskId)) return;

    // Check if already cached
    const cached = getCachedTaskSnapshot(queryClient, taskId, effectiveProjectId);
    if (cached) {
      return;
    }

    try {
      await fetchAndSeedTaskQuery(queryClient, taskId, effectiveProjectId);
    } catch {
      // Silently fail - prefetch is best-effort
    }
  }, [queryClient]);

  return prefetch;
}

import { QueryClient } from '@tanstack/react-query';
import type { GenerationRow } from '@/domains/generation/types';
import { Task } from '@/types/tasks';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { resolveTaskProjectScope } from '@/shared/lib/tasks/resolveTaskProjectScope';
import { getGenerationId } from '@/shared/lib/media/mediaTypeHelpers';
import { fetchAndSeedTaskQuery, getCachedTaskSnapshot } from '@/shared/hooks/tasks/useTasks';
import {
  resolveGenerationTaskMappings,
  toGenerationTaskMappingCacheEntry,
  type GenerationTaskMappingCacheEntry,
  type GenerationTaskMappingStatus,
} from '@/shared/lib/tasks/generationTaskRepository';

interface PreloadGenerationTaskMappingsOptions {
  batchSize?: number;
  delayBetweenBatches?: number;
  preloadFullTaskData?: boolean;
}

interface GenerationWithTaskData extends GenerationRow {
  taskId?: string | null;
  taskData?: Task | null;
  taskMappingStatus?: GenerationTaskMappingStatus;
  taskMappingError?: string;
}

/** Preload cached generation -> task mappings for a batch of generations. */
export async function preloadGenerationTaskMappings(
  queryClient: QueryClient,
  generationIds: string[],
  projectId: string | null,
  options: PreloadGenerationTaskMappingsOptions = {},
) {
  const effectiveProjectId = resolveTaskProjectScope(projectId);
  const {
    batchSize = 5,
    delayBetweenBatches = 200,
    preloadFullTaskData = false,
  } = options;

  for (let i = 0; i < generationIds.length; i += batchSize) {
    const batch = generationIds.slice(i, i + batchSize);

    const mappings = await resolveGenerationTaskMappings(batch, {
      projectId: effectiveProjectId ?? undefined,
    });
    let reportedBatchQueryFailure = false;

    const prefetchTasks: Array<Promise<unknown>> = [];

    batch.forEach((generationId) => {
      const mapping = mappings.get(generationId);
      const cacheEntry = toGenerationTaskMappingCacheEntry(mapping);
      queryClient.setQueryData<GenerationTaskMappingCacheEntry>(
        taskQueryKeys.generationMapping(generationId),
        cacheEntry,
      );

      if (!reportedBatchQueryFailure && cacheEntry.status === 'query_failed' && cacheEntry.queryError) {
        reportedBatchQueryFailure = true;
        normalizeAndPresentError(new Error(cacheEntry.queryError), {
          context: 'GenerationTaskCache',
          showToast: false,
        });
      }

      if (preloadFullTaskData && effectiveProjectId && cacheEntry.taskId && cacheEntry.status === 'ok') {
        prefetchTasks.push(fetchAndSeedTaskQuery(queryClient, cacheEntry.taskId, effectiveProjectId));
      }
    });

    if (prefetchTasks.length > 0) {
      await Promise.all(prefetchTasks);
    }

    if (i + batchSize < generationIds.length) {
      await new Promise((resolve) => setTimeout(resolve, delayBetweenBatches));
    }
  }
}

export function mergeGenerationsWithTaskData(
  generations: GenerationRow[],
  queryClient: QueryClient,
  projectId: string | null,
): GenerationWithTaskData[] {
  const effectiveProjectId = resolveTaskProjectScope(projectId);

  return generations.map((generation) => {
    const generationId = getGenerationId(generation);
    const cachedMapping = queryClient.getQueryData<GenerationTaskMappingCacheEntry>(
      taskQueryKeys.generationMapping(generationId),
    );
    const taskId = cachedMapping?.taskId || null;
    const taskData = (taskId && effectiveProjectId)
      ? getCachedTaskSnapshot(queryClient, taskId, effectiveProjectId) ?? null
      : null;
    const taskMappingStatus = cachedMapping?.status ?? (taskId ? 'ok' : 'not_loaded');

    return {
      ...generation,
      taskId,
      taskData,
      taskMappingStatus,
      ...(cachedMapping?.queryError ? { taskMappingError: cachedMapping.queryError } : {}),
    };
  });
}

/**
 * RealtimeProvider - Manages realtime connection and provides status to the app
 *
 * This provider:
 * 1. Connects to the realtime service when a project is selected
 * 2. Wires raw events from connection → processor → invalidation
 * 3. Exposes connection status to the component tree
 *
 */

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo, useRef } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { useProject } from '@/shared/contexts/ProjectContext';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { isTaskDbRow, mapTaskDbRowToTask } from '@/shared/lib/taskRowMapper';
import { getRealtimeConnection } from '@/shared/realtime/RealtimeConnection';
import { realtimeEventProcessor } from '@/shared/realtime/RealtimeEventProcessor';
import { dataFreshnessManager } from '@/shared/realtime/DataFreshnessManager';
import { useRealtimeInvalidation } from '@/shared/hooks/useRealtimeInvalidation';
import { fetchAndSeedTaskQuery, getCachedTaskSnapshot } from '@/shared/hooks/tasks/useTasks';
import {
  resetRealtimeTaskScope,
  upsertRealtimeTaskSnapshot,
} from '@/shared/state/realtimeStore';
import type { ConnectionState, ConnectionStatus, RawDatabaseEvent } from '@/shared/realtime/types';

// =============================================================================
// Context
// =============================================================================

interface RealtimeContextValue {
  /** Current connection status */
  status: ConnectionStatus;
  /** Whether currently connected */
  isConnected: boolean;
  /** Whether connection is in progress */
  isConnecting: boolean;
  /** Whether in a failed state (exhausted retries) */
  isFailed: boolean;
  /** Error message if any */
  error: string | null;
  /** Current reconnect attempt (0 if not reconnecting) */
  reconnectAttempt: number;
  /** Manually trigger reconnection */
  reconnect: () => void;
}

const RealtimeContext = createContext<RealtimeContextValue>({
  status: 'disconnected',
  isConnected: false,
  isConnecting: false,
  isFailed: false,
  error: null,
  reconnectAttempt: 0,
  reconnect: () => {},
});

export const useRealtime = () => useContext(RealtimeContext);

// =============================================================================
// Provider
// =============================================================================

interface RealtimeProviderProps {
  children: React.ReactNode;
}

function getTaskRowStringField(value: unknown, field: 'id' | 'project_id'): string | null {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return null;
  }

  const fieldValue = (value as Record<string, unknown>)[field];
  return typeof fieldValue === 'string' && fieldValue.trim().length > 0 ? fieldValue : null;
}

export function RealtimeProvider({ children }: RealtimeProviderProps) {
  const { selectedProjectId } = useProject();
  const queryClient = useQueryClient();
  const realtimeConnection = useMemo(() => getRealtimeConnection(), []);
  const [connectionState, setConnectionState] = useState<ConnectionState>(() =>
    realtimeConnection.getState()
  );
  const activeProjectIdRef = useRef<string | null>(null);

  // Set up the invalidation hook (subscribes to processed events)
  useRealtimeInvalidation();

  const hydrateTaskSnapshot = useCallback(async (event: RawDatabaseEvent) => {
    if (event.table !== 'tasks' || (event.eventType !== 'INSERT' && event.eventType !== 'UPDATE')) {
      return;
    }

    const fallbackProjectId = getTaskRowStringField(event.new, 'project_id')
      ?? getTaskRowStringField(event.old, 'project_id')
      ?? activeProjectIdRef.current;

    if (isTaskDbRow(event.new)) {
      upsertRealtimeTaskSnapshot(mapTaskDbRowToTask(event.new), fallbackProjectId);
      return;
    }

    const taskId = getTaskRowStringField(event.new, 'id') ?? getTaskRowStringField(event.old, 'id');
    if (!taskId || !fallbackProjectId) {
      return;
    }

    try {
      const cachedTask = getCachedTaskSnapshot(queryClient, taskId, fallbackProjectId);

      if (cachedTask !== undefined) {
        if (cachedTask && activeProjectIdRef.current === fallbackProjectId) {
          upsertRealtimeTaskSnapshot(cachedTask, fallbackProjectId);
        }
        return;
      }

      const fetchedTask = await fetchAndSeedTaskQuery(queryClient, taskId, fallbackProjectId);

      if (fetchedTask && activeProjectIdRef.current === fallbackProjectId) {
        upsertRealtimeTaskSnapshot(fetchedTask, fallbackProjectId);
      }
    } catch (error) {
      normalizeAndPresentError(error, {
        context: 'RealtimeProvider.hydrateTaskSnapshot',
        showToast: false,
        logData: {
          taskId,
          projectId: fallbackProjectId,
          eventType: event.eventType,
        },
      });
    }
  }, [queryClient]);

  // Wire connection events → processor
  useEffect(() => {
    const unsubscribe = realtimeConnection.onEvent((event) => {
      void hydrateTaskSnapshot(event);
      realtimeEventProcessor.process(event);
    });
    return unsubscribe;
  }, [hydrateTaskSnapshot, realtimeConnection]);

  // Subscribe to connection status changes
  useEffect(() => {
    const unsubscribe = realtimeConnection.onStatusChange((state) => {
      setConnectionState(state);
    });
    return unsubscribe;
  }, [realtimeConnection]);

  // Connect/disconnect when project changes
  useEffect(() => {
    const previousProjectId = activeProjectIdRef.current;

    if (previousProjectId && previousProjectId !== selectedProjectId) {
      resetRealtimeTaskScope(previousProjectId);
    }

    if (!selectedProjectId) {
      activeProjectIdRef.current = null;
      realtimeConnection.disconnect();
      dataFreshnessManager.reset();
      return;
    }

    if (previousProjectId !== selectedProjectId) {
      resetRealtimeTaskScope(selectedProjectId);
    }

    activeProjectIdRef.current = selectedProjectId;
    realtimeConnection.connect(selectedProjectId);

    return () => {
      // Don't disconnect on cleanup - let the next effect handle it
      // This prevents disconnect/reconnect when the component re-renders
    };
  }, [selectedProjectId, realtimeConnection]);

  // Clean up on unmount
  useEffect(() => {
    return () => {
      if (activeProjectIdRef.current) {
        resetRealtimeTaskScope(activeProjectIdRef.current);
      }
      realtimeEventProcessor.clear();
    };
  }, []);

  // Manual reconnect function
  const reconnect = useCallback(() => {
    if (selectedProjectId) {
      realtimeConnection.reset();
      realtimeConnection.connect(selectedProjectId);
    }
  }, [selectedProjectId, realtimeConnection]);

  // Derive context value from connection state
  const contextValue: RealtimeContextValue = {
    status: connectionState.status,
    isConnected: connectionState.status === 'connected',
    isConnecting: connectionState.status === 'connecting',
    isFailed: connectionState.status === 'failed',
    error: connectionState.error,
    reconnectAttempt: connectionState.reconnectAttempt,
    reconnect,
  };

  return (
    <RealtimeContext.Provider value={contextValue}>
      {children}
    </RealtimeContext.Provider>
  );
}

